-- helpers
local function _tfind(t,v) for i,x in t do if x==v then return i end end end
local function _tadd(t,v) if not _tfind(t,v) then table.insert(t,v) end end
local function _tremove(t,v) local i=_tfind(t,v); if i then table.remove(t,i) end end

-- object-aware Library helpers
local function _findSong(id)
    for i,s in ipairs(_D.Library.Songs) do
        local sid = (type(s)=="table") and s.SongId or s
        if sid == id then return i, s end
    end
end
local function _findArtist(n)
    for i,a in ipairs(_D.Library.Artists) do
        local name = (type(a)=="table") and a.Name or a
        if name == n then return i, a end
    end
end

-- Playback monthly helpers
local _MonthNames = {"January","February","March","April","May","June","July","August","September","October","November","December"}
local function _pbMonth() return _MonthNames[tonumber(os.date("%m"))] end
local function _pbYear()  return tonumber(os.date("%Y")) end
local function _pbMonthData()
    if _D.Playback.Current.Year ~= _pbYear() then
        -- year rollover: summarise current into previous
        local prev = {Year=_D.Playback.Current.Year, TopArtists={}, TopSongs={}, PlayedSongs=0, PlayedArtist=0, TotalDuration=0}
        local function inc(list, key, val)
            for _,e in ipairs(list) do if e[key]==val then e.Plays=(e.Plays or 0)+1; return end end
            table.insert(list, {[key]=val, Plays=1})
        end
        for _,md in pairs(_D.Playback.Current.Months) do
            for _,a in ipairs(md.Artists or {}) do inc(prev.TopArtists,"Name",a.Name); prev.PlayedArtist+=a.Plays end
            for _,s in ipairs(md.Songs   or {}) do inc(prev.TopSongs,  "SongId",s.SongId); prev.PlayedSongs+=s.Plays end
            prev.TotalDuration += (md.Duration or 0)
        end
        table.sort(prev.TopArtists, function(a,b) return a.Plays>b.Plays end)
        table.sort(prev.TopSongs,   function(a,b) return a.Plays>b.Plays end)
        _D.Playback = { Current={Year=_pbYear(), Months={}}, Previous=prev }
    end
    local m = _pbMonth()
    if not _D.Playback.Current.Months[m] then
        _D.Playback.Current.Months[m] = {Artists={}, Songs={}, Duration=0}
    end
    return _D.Playback.Current.Months[m]
end
local function _pbInc(list, key, val)
    for _,e in ipairs(list) do if e[key]==val then e.Plays=(e.Plays or 0)+1; return end end
    table.insert(list, {[key]=val, Plays=1})
end

