local _HS         = game:GetService("HttpService")
local _SAVE_FILE  = "Masters_data.json"
local _SAVE_DIRTY = false   -- debounce: only write when something changed

local function _DeepCopy(t)
    if type(t) ~= "table" then return t end
    local c = {}
    for k,v in pairs(t) do c[k] = _DeepCopy(v) end
    return c
end

-- Write _D's persistent slices to disk
local function _SaveData()
    if not writefile then return end        -- not in an executor that exposes writefile
    local payload = {
        Algorithm = {
            Songs   = _DeepCopy(_D.Algorithm.Songs),
            Artists = _DeepCopy(_D.Algorithm.Artists),
            Tags    = _DeepCopy(_D.Algorithm.Tags),
        },
        Library = {
            Songs    = _DeepCopy(_D.Library.Songs),
            Artists  = _DeepCopy(_D.Library.Artists),
            Playlist = _DeepCopy(_D.Library.Playlist),
        },
        Preferences = {
            Songs   = _DeepCopy(_D.Preferences.Songs),
            Artists = _DeepCopy(_D.Preferences.Artists),
        },
        Sharing  = _DeepCopy(_D.Sharing),
        Playback = _DeepCopy(_D.Playback),
        Session  = _DeepCopy(_D.Session),
        Settings = _DeepCopy(_D.Settings),   -- persist user config (crossfade, equalizer, socials, extras)
    }
    local ok, encoded = pcall(function() return _HS:JSONEncode(payload) end)
    if ok and encoded then
        pcall(writefile, _SAVE_FILE, encoded)
    end
    _SAVE_DIRTY = false
end

-- Debounced save: coalesces rapid mutations into one write per second
task.spawn(function()
    while true do
        task.wait(1)
        if _SAVE_DIRTY then _SaveData() end
    end
end)

local function _MarkDirty() _SAVE_DIRTY = true end

-- ─────────────────────────────────────────────────────────────
-- [ALGO ENGINE] Session buffer + decay  (mirrors rbxmx Algorithm module)
-- ─────────────────────────────────────────────────────────────
local _ALGO_SESSION_INCREMENT = 1
local _ALGO_BASE_DECAY        = 0.95
local _ALGO_MAX_INACTIVE      = 60 * 60 * 24 * 30  -- 30 days
local _ALGO_TOP_LIMIT         = 100

-- Session-level buffer (dict format, accumulated per-session, flushed on save)
local _AlgoBuffer = {
    Artists         = {},   -- [name]  = count
    Songs           = {},   -- [id]    = count
    Tags            = {},   -- [tag]   = count
    SessionMultiplier = 1,
}

-- Sort _D.Algorithm.* by Relevance desc
local function _AlgoArrange(list)
    table.sort(list, function(a, b) return (a.Relevance or 0) > (b.Relevance or 0) end)
end

-- Trim list to top N entries (must be sorted first)
local function _AlgoTrimTopN(list)
    while #list > _ALGO_TOP_LIMIT do
        table.remove(list, #list)
    end
end

-- Additive IncrementEntry: adds Amount to existing entry or inserts new one
local function _AlgoIncrementEntry(list, keyName, keyValue, amount)
    local now = os.time()
    for _, entry in list do
        if entry[keyName] == keyValue then
            entry.Relevance = (entry.Relevance or 0) + amount
            entry.LastUpdate = now
            return
        end
    end
    if keyName == "SongId" then
        table.insert(list, {[keyName] = tonumber(keyValue) or keyValue, Relevance = amount, LastUpdate = now})
    else
        table.insert(list, {[keyName] = keyValue, Relevance = amount, LastUpdate = now})
    end
end

-- Time-aware decay applied to persisted data before merging new session
local function _AlgoApplyDecay(list)
    local now = os.time()
    for _, entry in list do
        local lastUpdate   = entry.LastUpdate or now
        local inactiveTime = math.clamp(now - lastUpdate, 0, _ALGO_MAX_INACTIVE)
        local timeFactor   = inactiveTime / _ALGO_MAX_INACTIVE
        local decayMult    = _ALGO_BASE_DECAY ^ (1 + timeFactor * 4)
        entry.Relevance    = math.floor((entry.Relevance or 0) * decayMult)
    end
end

-- Flush session buffer into _D.Algorithm (mirrors rbxmx Flush→DataStore:UpdateAsync)
local function _AlgoFlush()
    -- 1. Decay existing stored data first
    _AlgoApplyDecay(_D.Algorithm.Artists)
    _AlgoApplyDecay(_D.Algorithm.Songs)
    _AlgoApplyDecay(_D.Algorithm.Tags)

    -- 2. Merge session buffer (additive)
    for artistName, count in _AlgoBuffer.Artists do
        _AlgoIncrementEntry(_D.Algorithm.Artists, "Name",   artistName, count)
    end
    for songId, count in _AlgoBuffer.Songs do
        _AlgoIncrementEntry(_D.Algorithm.Songs,   "SongId", songId,     count)
    end
    for tag, count in _AlgoBuffer.Tags do
        _AlgoIncrementEntry(_D.Algorithm.Tags,    "Tag",    tag,        count)
    end

    -- 3. Sort + trim
    _AlgoArrange(_D.Algorithm.Artists);  _AlgoTrimTopN(_D.Algorithm.Artists)
    _AlgoArrange(_D.Algorithm.Songs);    _AlgoTrimTopN(_D.Algorithm.Songs)
    _AlgoArrange(_D.Algorithm.Tags);     _AlgoTrimTopN(_D.Algorithm.Tags)

    -- 4. Clear buffer, reset multiplier
    _AlgoBuffer.Artists          = {}
    _AlgoBuffer.Songs            = {}
    _AlgoBuffer.Tags             = {}
    _AlgoBuffer.SessionMultiplier = 1

    _MarkDirty()
end

-- Periodic flush every 60s (mirrors rbxmx FLUSH_INTERVAL)
task.spawn(function()
    while true do
        task.wait(60)
        _AlgoFlush()
    end
end)

-- Merge saved songs/artists/playlists back into _D on startup
local function _LoadData()
    if not readfile or not isfile then return end
    if not pcall(isfile, _SAVE_FILE) then return end
    local ok_check, exists = pcall(isfile, _SAVE_FILE)
    if not ok_check or not exists then return end

    local ok, raw = pcall(readfile, _SAVE_FILE)
    if not ok or not raw or raw == "" then return end

    local ok2, data = pcall(function() return _HS:JSONDecode(raw) end)
    if not ok2 or type(data) ~= "table" then return end

    -- Algorithm: merge saved songs/artists/tags (deduplicate by key)
    if type(data.Algorithm) == "table" then
        -- Additive merge (mirrors rbxmx IncrementEntry): loaded saved relevance is
        -- added on top of current in-memory value, not replaced by "higher wins".
        local function _mergeAlgo(dst, src, keyName)
            if type(src) ~= "table" then return end
            for _, e in ipairs(src) do
                local found = false
                for _, d in ipairs(dst) do
                    if d[keyName] == e[keyName] then
                        d.Relevance  = (d.Relevance or 0) + (e.Relevance or 0)
                        d.LastUpdate = math.max(d.LastUpdate or 0, e.LastUpdate or 0)
                        found = true
                        break
                    end
                end
                if not found then
                    table.insert(dst, {[keyName] = e[keyName], Relevance = e.Relevance or 0, LastUpdate = e.LastUpdate or os.time()})
                end
            end
        end
        _mergeAlgo(_D.Algorithm.Songs,   data.Algorithm.Songs,   "SongId")
        _mergeAlgo(_D.Algorithm.Artists, data.Algorithm.Artists, "Name")
        _mergeAlgo(_D.Algorithm.Tags,    data.Algorithm.Tags,    "Tag")
        -- After merging, sort + trim so in-memory stays clean
        _AlgoArrange(_D.Algorithm.Artists);  _AlgoTrimTopN(_D.Algorithm.Artists)
        _AlgoArrange(_D.Algorithm.Songs);    _AlgoTrimTopN(_D.Algorithm.Songs)
        _AlgoArrange(_D.Algorithm.Tags);     _AlgoTrimTopN(_D.Algorithm.Tags)
    end

    -- Library: songs (objects {SongId, Pin}) & artists (objects {Name, Pin})
    if type(data.Library) == "table" then
        if type(data.Library.Songs) == "table" then
            for _, s in ipairs(data.Library.Songs) do
                local id = (type(s)=="table") and s.SongId or s
                if not _findSong(id) then
                    table.insert(_D.Library.Songs, {SongId=tonumber(id) or id, Pin=(type(s)=="table" and s.Pin or false)})
                end
            end
        end
        if type(data.Library.Artists) == "table" then
            for _, a in ipairs(data.Library.Artists) do
                local n = (type(a)=="table") and a.Name or a
                if not _findArtist(n) then
                    table.insert(_D.Library.Artists, {Name=n, Pin=(type(a)=="table" and a.Pin or false)})
                end
            end
        end
        if type(data.Library.Playlist) == "table" then
            local existing = {}
            for _, pl in ipairs(_D.Library.Playlist) do existing[pl.PlaylistId] = true end
            for _, pl in ipairs(data.Library.Playlist) do
                if pl.PlaylistId and not existing[pl.PlaylistId] then
                    table.insert(_D.Library.Playlist, pl)
                    existing[pl.PlaylistId] = true
                end
            end
        end
    end

    -- Preferences
    if type(data.Preferences) == "table" then
        if type(data.Preferences.Songs) == "table" then
            for _, id in ipairs(data.Preferences.Songs.Favorite or {}) do _tadd(_D.Preferences.Songs.Favorite, id) end
            for _, id in ipairs(data.Preferences.Songs.Dislike  or {}) do _tadd(_D.Preferences.Songs.Dislike,  id) end
        end
        if type(data.Preferences.Artists) == "table" then
            for _, n in ipairs(data.Preferences.Artists.Block or {}) do _tadd(_D.Preferences.Artists.Block, n) end
        end
    end

    -- Sharing inbox
    if type(data.Sharing) == "table" then
        for _, item in ipairs(data.Sharing) do
            table.insert(_D.Sharing, item)
        end
    end

    -- Playback monthly stats
    if type(data.Playback) == "table" then
        if type(data.Playback.Current) == "table" then
            _D.Playback.Current = data.Playback.Current
        end
        if data.Playback.Previous then
            _D.Playback.Previous = data.Playback.Previous
        end
    end

    -- Session (last playback position)
    if type(data.Session) == "table" then
        for k,v in pairs(data.Session) do
            if _D.Session[k] ~= nil then _D.Session[k] = v end
        end
    end

    -- Settings (crossfade, equalizer, extras, socials …)
    if type(data.Settings) == "table" then
        for category, savedCat in pairs(data.Settings) do
            if type(_D.Settings[category]) == "table" and type(savedCat) == "table" then
                for key, savedVal in pairs(savedCat) do
                    if _D.Settings[category][key] ~= nil then
                        if type(savedVal) == "table" and type(_D.Settings[category][key]) == "table" then
                            -- nested table (e.g. Crossfade, Equalizer)
                            for k2, v2 in pairs(savedVal) do
                                if _D.Settings[category][key][k2] ~= nil then
                                    _D.Settings[category][key][k2] = v2
                                end
                            end
                        else
                            _D.Settings[category][key] = savedVal
                        end
                    end
                end
            end
        end
    end

    print("[Masters] Saved data loaded from " .. _SAVE_FILE)
end

_LoadData()     -- restore on startup

-- ─────────────────────────────────────────────────────────────
-- [2] FAKE REMOTE FACTORIES
-- ─────────────────────────────────────────────────────────────
local function RF(fn) -- RemoteFunction stub
    return setmetatable({},{
        __index=function(_,k)
            if k=="InvokeServer" then return function(_,...) return fn(...) end end
            if k=="OnClientInvoke" then return nil end
        end
    })
end
local function RE(fn) -- RemoteEvent stub
    local cbs={}
    return setmetatable({},{
        __index=function(_,k)
            if k=="FireServer" then return function(_,...) if fn then fn(...) end end end
            if k=="OnClientEvent" then
                return {Connect=function(_,cb) table.insert(cbs,cb); return {Connected=true,Disconnect=function()end} end}
            end
        end,
        __newindex=function(_,k,v)end,
        _fire=function(_,...) for _,cb in cbs do task.spawn(cb,...) end end
    })
end
local function BF(fn) -- BindableFunction stub
    return {Invoke=function(_,...) return fn(...) end}
end

-- ─────────────────────────────────────────────────────────────
-- [3] FAKE EVENTS TABLE  (mirrors Events folder hierarchy)
-- ─────────────────────────────────────────────────────────────
local fakeEvents = {
    Main = {
        Algorithm = {
            FetchAlgorithm  = RF(function()
                -- Flush any buffered session data first
                _AlgoFlush()
                -- Sort + trim so callers always get top-N by Relevance (mirrors rbxmx)
                _AlgoArrange(_D.Algorithm.Artists);  _AlgoTrimTopN(_D.Algorithm.Artists)
                _AlgoArrange(_D.Algorithm.Songs);    _AlgoTrimTopN(_D.Algorithm.Songs)
                _AlgoArrange(_D.Algorithm.Tags);     _AlgoTrimTopN(_D.Algorithm.Tags)
                return _D.Algorithm
            end),
            AddArtist       = RE(function(name)
                if not name then return end
                local weight = math.floor(_AlgoBuffer.SessionMultiplier)
                _AlgoBuffer.Artists[name] = (_AlgoBuffer.Artists[name] or 0) + weight
                _AlgoBuffer.SessionMultiplier += _ALGO_SESSION_INCREMENT
            end),
            AddSong         = RE(function(songId)
                if not songId then return end
                local id = tostring(tonumber(songId) or songId)
                local weight = math.floor(_AlgoBuffer.SessionMultiplier)
                _AlgoBuffer.Songs[id] = (_AlgoBuffer.Songs[id] or 0) + weight
                _AlgoBuffer.SessionMultiplier += _ALGO_SESSION_INCREMENT
            end),
            AddTags         = RE(function(tag)
                if not tag then return end
                local weight = math.floor(_AlgoBuffer.SessionMultiplier)
                _AlgoBuffer.Tags[tag] = (_AlgoBuffer.Tags[tag] or 0) + weight
                _AlgoBuffer.SessionMultiplier += _ALGO_SESSION_INCREMENT
            end),
        },
        Preferences = {
            FetchPreference = RF(function() return _D.Preferences end),
            FavoriteSong    = RF(function(id,s)
                if s then _tremove(_D.Preferences.Songs.Dislike,id); _tadd(_D.Preferences.Songs.Favorite,id)
                else _tremove(_D.Preferences.Songs.Favorite,id) end
                _MarkDirty()
                return true
            end),
            DislikeSong     = RF(function(id,s)
                if s then _tremove(_D.Preferences.Songs.Favorite,id); _tadd(_D.Preferences.Songs.Dislike,id)
                else _tremove(_D.Preferences.Songs.Dislike,id) end
                _MarkDirty()
                return true
            end),
            BlockArtist     = RF(function(n,s)
                if s then _tadd(_D.Preferences.Artists.Block,n)
                else _tremove(_D.Preferences.Artists.Block,n) end
                _MarkDirty()
                return true
            end),
            IsSongFavorite  = RF(function(id) return _tfind(_D.Preferences.Songs.Favorite,id)~=nil end),
            IsSongDislike   = RF(function(id) return _tfind(_D.Preferences.Songs.Dislike,id)~=nil end),
            IsArtistBlock   = RF(function(n) return _tfind(_D.Preferences.Artists.Block,n)~=nil end),
            GetSongStatus   = RF(function(id)
                if _tfind(_D.Preferences.Songs.Favorite,id) then return "Favorited"
                elseif _tfind(_D.Preferences.Songs.Dislike,id) then return "Disliked"
                else return nil end
            end),
            GetArtistStatus = RF(function(n)
                return _tfind(_D.Preferences.Artists.Block,n) and "Blocked" or nil
            end),
        },
        Library = {
            FetchLibrary    = RF(function() return _D.Library end),
            SetSong         = RF(function(id,s)
                if s then
                    if not _findSong(id) then
                        if #_D.Library.Songs >= 30 then return false, "limit" end
                        table.insert(_D.Library.Songs, {SongId=tonumber(id) or id, Pin=false})
                        _MarkDirty()
                    end
                else
                    local i = _findSong(id)
                    if i then table.remove(_D.Library.Songs,i); _MarkDirty() end
                end
                return true
            end),
            IsSongSaved     = RF(function(id) return _findSong(id)~=nil end),
            SetArtist       = RF(function(n,s)
                if s then
                    if not _findArtist(n) then
                        if #_D.Library.Artists >= 30 then return false, "limit" end
                        table.insert(_D.Library.Artists, {Name=n, Pin=false})
                        _MarkDirty()
                    end
                else
                    local i = _findArtist(n)
                    if i then table.remove(_D.Library.Artists,i); _MarkDirty() end
                end
                return true
            end),
            IsArtistSaved   = RF(function(n) return _findArtist(n)~=nil end),
            CreatePlaylist  = RF(function(info)
                if #_D.Library.Playlist >= 30 then return false, "limit" end
                -- deduplicate name
                local wantedName = (info and info.Name) or "Playlist"
                local function nameTaken(n)
                    for _,pl in ipairs(_D.Library.Playlist) do if pl.Name==n then return true end end
                end
                while nameTaken(wantedName) do wantedName = wantedName.." (Copy)" end
                local id = "MASTERSPLAYLIST:"..tostring(tick()).."_"..tostring(client.UserId)
                table.insert(_D.Library.Playlist,{
                    PlaylistId = id,
                    Name       = wantedName,
                    Cover      = (info and info.Cover) or "",
                    CreatorId  = client.UserId,
                    Private    = true,
                    Pin        = false,
                    Songs      = {},
                    Updated    = os.time(),
                })
                _MarkDirty()
                return true, id
            end),
            SetSongToPlaylist = RF(function(plId,songId,s)
                for _,pl in _D.Library.Playlist do
                    if pl.PlaylistId==plId then
                        if s then _tadd(pl.Songs,songId) else _tremove(pl.Songs,songId) end
                        _MarkDirty()
                        return true
                    end
                end; return false
            end),
            SetPlaylistProperty = RF(function(plId,prop,val)
                for _,pl in _D.Library.Playlist do
                    if pl.PlaylistId==plId then pl[prop]=val; _MarkDirty(); return true end
                end; return false
            end),
            AddPublicPlaylist  = RF(function(creatorId, plId, duplicateCopy)
                if #_D.Library.Playlist >= 30 then return false, "limit" end
                -- In executor we don't have access to other players' DataStores;
                -- return true so the UI flow doesn't break.
                return true
            end),
            Pin                = RE(function(type_, identifier, state)
                if type_ == "Song" then
                    local i,s = _findSong(identifier)
                    if s and type(s)=="table" then s.Pin=state; _MarkDirty() end
                elseif type_ == "Artist" then
                    local i,a = _findArtist(identifier)
                    if a and type(a)=="table" then a.Pin=state; _MarkDirty() end
                elseif type_ == "Playlist" then
                    for _,pl in ipairs(_D.Library.Playlist) do
                        if pl.PlaylistId==identifier then pl.Pin=state; _MarkDirty(); break end
                    end
                end
            end),
            IsPinned           = RF(function(type_, identifier)
                if type_ == "Song" then
                    local _,s = _findSong(identifier)
                    return s and type(s)=="table" and s.Pin or false
                elseif type_ == "Artist" then
                    local _,a = _findArtist(identifier)
                    return a and type(a)=="table" and a.Pin or false
                elseif type_ == "Playlist" then
                    for _,pl in ipairs(_D.Library.Playlist) do
                        if pl.PlaylistId==identifier then return pl.Pin or false end
                    end
                end
                return false
