            local _SHEETS_ID  = "1iJRuAArdm2fSobb0R1T4pLdaEKyyseqSsRhpyD9D7cA"
            local _SHEETS_URL = "https://sheets.googleapis.com/v4/spreadsheets/%s/values/%s?key=%s"
            local _SHEET_NAME = "Lyrics"

            -- HTTP compat: executor env
            local function httpGet(url)
                if syn and syn.request then
                    local r = syn.request({Url=url, Method="GET"})
                    return r and r.Body
                elseif request then
                    local r = request({Url=url, Method="GET"})
                    return r and r.Body
                else
