            local function fetchRange(range)
                local encoded = _HS:UrlEncode(range)
                local url = string.format(_SHEETS_URL, _SHEETS_ID, encoded, _SHEETS_KEY)
                local ok, body = pcall(httpGet, url)
                if not ok or not body then return nil end
                local ok2, data = pcall(function() return _HS:JSONDecode(body) end)
                if not ok2 or not data or not data.values then return nil end
                return data
            end

            -- Pre-load index async
            local _cachedIndex = nil
            task.spawn(function()
                local data = fetchRange(_SHEET_NAME .. "!A2")
                if not data then
                    warn("Masters LyricsEngine: Failed to fetch index")
                    return
                end
                local raw = data.values[1][1]
                local idx = {}
                for entry in raw:gmatch("[^,]+") do
                    local songId, key = entry:match("%s*(%d+):(%S+)")
                    if songId and key then
                        idx[songId] = _SHEET_NAME .. "!" .. key
                    end
                end
                _cachedIndex = idx
                local n = 0
                for _ in pairs(idx) do n += 1 end
                print("Masters LyricsEngine: Loaded index,", n, "songs")
            end)

            return {
                GetLyricsIndex = RF(function()
                    return _cachedIndex or {}
                end),
                GetLyrics = RF(function(rangeKey)
                    if not rangeKey then return nil end
                    local data = fetchRange(rangeKey)
                    if not data then return nil end
                    local ok, parsed = pcall(function()
                        return _HS:JSONDecode(data.values[1][1])
                    end)
                    return ok and parsed or nil
