-- ─────────────────────────────────────────────────────────────
-- [4] FAKE STORAGE OBJECT  (proxy table, not real Instance)
-- ─────────────────────────────────────────────────────────────
local _modProxies = setmetatable({},{
    __index = function(_,name)
        return {_isMod=true, _name=name, Name=name,
                ClassName="ModuleScript",
                WaitForChild=function(_,k) return {_isMod=true,_name=k,Name=k} end}
    end
})

local fakeStorage = {
    Events  = fakeEvents,
    Modules = _modProxies,
    Name    = "Masters(Storage)",
    WaitForChild = function(_,k)
        if k=="Events"  then return fakeEvents end
        if k=="Modules" then return _modProxies end
        return nil
    end,
    FindFirstChild = function(_,k)
        if k=="Events"  then return fakeEvents end
        if k=="Modules" then return _modProxies end
        return nil
    end,
}

-- ─────────────────────────────────────────────────────────────
-- [5] FAKE ReplicatedStorage  (wraps real one, intercepts WFC)
-- ─────────────────────────────────────────────────────────────
local _realRS = game:GetService("ReplicatedStorage")
local fakeRS  = setmetatable({},{
    __index = function(_,k)
        if k=="WaitForChild" or k=="FindFirstChild" then
            return function(_, name, ...)
                if name=="Masters(Storage)" then return fakeStorage end
                return _realRS[k](_realRS, name, ...)
            end
        end
        local v = _realRS[k]
        if type(v)=="function" then
            return function(_, ...) return _realRS[k](_realRS, ...) end
        end
        return v
    end,
    __newindex = function(_,k,v) _realRS[k]=v end,
})

-- ─────────────────────────────────────────────────────────────
-- [6] MODULE CACHE + LOADER
-- ─────────────────────────────────────────────────────────────
local _mc = {}   -- module cache: name -> module table

local function loadMod(name, src, extraEnv)
    local base = setmetatable(extraEnv or {},{__index=getfenv(0)})
    base.script = {
        Name="ModuleScript", ClassName="ModuleScript",
        Parent=_modProxies,
        WaitForChild=function(_,k) return {_isMod=true,_name=k,Name=k} end,
    }
    base.require = function(obj)
        if type(obj)=="table" and obj._isMod then
            return _mc[obj._name] or error("mod not cached: "..tostring(obj._name))
        end
        return require(obj)
    end
    base.game = setmetatable({},{
        __index=function(_,k)
            if k=="GetService" then
                return function(_, svcName)
                    if svcName=="ReplicatedStorage" then return fakeRS end
                    return game:GetService(svcName)
                end
            end
            local v = game[k]
            if type(v)=="function" then
                return function(_, ...) return game[k](game, ...) end
            end
            return v
        end,
        __newindex=function(_,k,v) game[k]=v end,
    })
    local fn,err = loadstring(src, "@Masters/"..name)
    if not fn then warn("[Masters] loadMod "..name.." parse error: "..tostring(err)); return {} end
    setfenv(fn, base)
    local ok,res = pcall(fn)
    if not ok then warn("[Masters] loadMod "..name.." runtime error: "..tostring(res)); return {} end
    return res or {}
end


