-- ─── STORAGE BUILDER: Items + Sounds (required by handler) ──────────────
do
    local _pgu2 = game:GetService("Players").LocalPlayer:WaitForChild("PlayerGui")
    local _ui   = _pgu2:WaitForChild("Masters", 10)
    if not _ui then warn("[Masters] UI not found for Storage build") return end

    local Storage = _ui:FindFirstChild("Storage")
    if not Storage then
        Storage = Instance.new("Folder")
        Storage.Name = "Storage"
        Storage.Parent = _ui
    end

    -- ── Sounds ────────────────────────────────────────────────────────────
    local Sounds = Instance.new("Folder")
    Sounds.Name = "Sounds"
    Sounds.Parent = Storage

    local tapSound = Instance.new("Sound")
    tapSound.Name       = "Tap"
    tapSound.SoundId    = "rbxassetid://3623733749"
    tapSound.Volume     = 0.5
    tapSound.RollOffMode = Enum.RollOffMode.InverseTapered
    tapSound.Parent     = Sounds

    -- ── Items ─────────────────────────────────────────────────────────────
    local Items = Instance.new("Configuration")
    Items.Name = "Items"
    Items.Parent = Storage

    -- helper: make invisible template Frame/ImageButton
    local function mk(class, name, parent)
        local i = Instance.new(class)
        i.Name   = name
        i.Parent = parent
        pcall(function() i.Visible = false end)
        pcall(function() i.BackgroundTransparency = 1 end)
        pcall(function() i.Size = UDim2.fromScale(1, 0) end)
        pcall(function() i.AutomaticSize = Enum.AutomaticSize.Y end)
        return i
    end
    local function mkLabel(name, parent)
        local l = Instance.new("TextLabel")
        l.Name = name; l.Parent = parent
        pcall(function() l.BackgroundTransparency = 1 l.Size = UDim2.fromScale(1,0) l.AutomaticSize = Enum.AutomaticSize.Y l.Text = "" end)
        return l
    end
    local function mkImage(name, parent)
        local i = Instance.new("ImageLabel")
        i.Name = name; i.Parent = parent
        pcall(function() i.BackgroundTransparency = 1 i.Size = UDim2.fromScale(1,1) end)
        return i
    end
    local function mkScale(parent)
        local s = Instance.new("UIScale"); s.Name = "scale"; s.Parent = parent; return s
    end
    local function mkList(parent)
        local l = Instance.new("UIListLayout"); l.Name = "list"; l.Parent = parent; return l
    end

    -- ── buildSongItem: direct RBXMX translation — NO AutomaticSize, UIFlexItem on Info ──
    -- Helper: build Photo ImageLabel inside Art (shared by all item types)
    local function buildSongPhoto(photo, cornerRadius)
        photo.BackgroundColor3 = Color3.fromRGB(37, 39, 44)
        photo.BackgroundTransparency = 0
        photo.Image = ""
        photo.ScaleType = Enum.ScaleType.Crop
        photo.Size = UDim2.new(1, 0, 1, 0)
        photo.Position = UDim2.new(0.5, 0, 0.5, 0)
        photo.AnchorPoint = Vector2.new(0.5, 0.5)
        photo.Visible = true
        local corner = Instance.new("UICorner"); corner.Name = "corner"; corner.Parent = photo
        pcall(function() corner.CornerRadius = UDim.new(0, cornerRadius) end)
        local sc = Instance.new("UIScale"); sc.Name = "scale"; sc.Parent = photo
        -- CurrentlyPlaying overlay (MastersPlayingVisual) — parsed từ rbxmx
        -- Visible=true, ẩn bằng GroupTransparency=1 (không phải Visible=false)
        -- ClipsDescendants=true để Icon/Shadow bị clip theo UICorner
        local cp = Instance.new("CanvasGroup"); cp.Name = "CurrentlyPlaying"; cp.Parent = photo
        cp.BackgroundColor3 = Color3.fromRGB(0,0,0); cp.BackgroundTransparency = 0.8
        cp.GroupTransparency = 1; cp.Visible = true; cp.ClipsDescendants = true
        cp.AnchorPoint = Vector2.new(0.5,0.5); cp.Position = UDim2.new(0.5,0,0.5,0); cp.Size = UDim2.new(1,0,1,0)
        pcall(function() cp:SetAttribute("Enabled", false) end)
        pcall(function()
            local cc = Instance.new("UICorner"); cc.Name = "corner"; cc.Parent = cp
            cc.CornerRadius = UDim.new(0, cornerRadius)
        end)
        -- Icon loa (rbxassetid://124376668827207), ScaleType=Fit, 50%×50%, căn giữa
        local cpIcon = Instance.new("ImageLabel"); cpIcon.Name = "Icon"; cpIcon.Parent = cp
        cpIcon.BackgroundTransparency = 1; cpIcon.Image = "rbxassetid://124376668827207"
        cpIcon.Size = UDim2.fromScale(0.5, 0.5)
        cpIcon.AnchorPoint = Vector2.new(0.5, 0.5); cpIcon.Position = UDim2.fromScale(0.5, 0.5)
        pcall(function() cpIcon.ScaleType = Enum.ScaleType.Fit end)
        -- Shadow glow sau icon (rbxassetid://122971705612181), 90%×90%, ImageTransparency=0.5
        local cpGlow = Instance.new("ImageLabel"); cpGlow.Name = "Shadow"; cpGlow.Parent = cp
        cpGlow.BackgroundTransparency = 1; cpGlow.Image = "rbxassetid://122971705612181"
        cpGlow.ImageTransparency = 0.5; cpGlow.ZIndex = 0
        cpGlow.Size = UDim2.fromScale(0.9, 0.9)
        cpGlow.AnchorPoint = Vector2.new(0.5, 0.5); cpGlow.Position = UDim2.fromScale(0.5, 0.5)
        pcall(function() cpGlow.ScaleType = Enum.ScaleType.Fit end)
        -- Hover overlay (for Big item glow animations)
        local hover = Instance.new("CanvasGroup"); hover.Name = "Hover"; hover.Parent = photo
        hover.BackgroundTransparency = 1; hover.GroupTransparency = 1
        hover.AnchorPoint = Vector2.new(0.5,0.5); hover.Position = UDim2.new(0.5,0,0.5,0); hover.Size = UDim2.new(1,0,1,0)
        local glow = Instance.new("Frame"); glow.Name = "Glow"; glow.Parent = hover
        glow.BackgroundTransparency = 1; glow.Size = UDim2.fromScale(0,0)
        pcall(function() glow:SetAttribute("Enabled", false) end)
        -- Pinned badge
        local pinned = Instance.new("Frame"); pinned.Name = "Pinned"; pinned.Parent = photo
        pinned.BackgroundTransparency = 1; pinned.Size = UDim2.fromScale(1,1); pinned.Visible = false
    end

    -- Helper: build Information frame (Title + Source, filled via UIFlexItem)
    local function buildSongInfo(info, titleSz, sourceSz, isHorizontal, alignTop)
        -- RBXMX: Size=(0,0,1,0) so UIListLayout stretches width (vertical) or height (horizontal);
        -- UIFlexItem(Fill) fills the layout fill-direction. NO AutomaticSize.
        info.BackgroundTransparency = 1; info.Visible = true; info.ClipsDescendants = false
        info.Size = isHorizontal and UDim2.new(0, 0, 1, 0) or UDim2.new(1, 0, 0, 0); info.LayoutOrder = 2
        -- UIFlexItem is REQUIRED — without it Information has 0 width/height in fill direction
        pcall(function()
            local fi = Instance.new("UIFlexItem"); fi.Name = "flex"; fi.Parent = info
            fi.FlexMode = Enum.UIFlexMode.Fill
        end)
        local il = Instance.new("UIListLayout"); il.Name = "list"; il.Parent = info
        il.FillDirection = Enum.FillDirection.Vertical; il.SortOrder = Enum.SortOrder.LayoutOrder
        il.Padding = UDim.new(0,0); il.HorizontalAlignment = Enum.HorizontalAlignment.Left
        -- VerticalAlignment=Center cho tất cả item — tránh text bị kéo lên trên
        il.VerticalAlignment = Enum.VerticalAlignment.Center
        local pad = Instance.new("UIPadding"); pad.Name = "padding"; pad.Parent = info
        pad.PaddingLeft = UDim.new(0,2); pad.PaddingRight = UDim.new(0,2)
        -- Title
        local title = Instance.new("TextLabel"); title.Name = "Title"; title.Parent = info
        title.BackgroundTransparency = 1; title.Visible = true
        title.Size = UDim2.new(1,0,0,titleSz); title.TextSize = titleSz
        title.TextColor3 = Color3.fromRGB(255,255,255); title.TextTransparency = 0
        title.Text = ""; title.TextTruncate = Enum.TextTruncate.None
        title.TextXAlignment = Enum.TextXAlignment.Left; title.LayoutOrder = 0
        pcall(function() title.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Medium, Enum.FontStyle.Normal) end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = title
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)
        -- Source (artist)
        local source = Instance.new("TextLabel"); source.Name = "Source"; source.Parent = info
        source.BackgroundTransparency = 1; source.Visible = true
        source.Size = UDim2.new(1,0,0,sourceSz); source.TextSize = sourceSz
        source.TextColor3 = Color3.fromRGB(255,255,255); source.TextTransparency = 0.5
        source.Text = ""; source.TextTruncate = Enum.TextTruncate.None
        source.TextXAlignment = Enum.TextXAlignment.Left; source.LayoutOrder = 0
        pcall(function() source.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Regular, Enum.FontStyle.Normal) end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = source
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)
    end

    local function buildSongItem(name)
        -- isRow = horizontal list-row layout (Small, Vertical, SearchResults, NowPlayingQueue, Playlist)
        -- isSearch = SearchResults-specific sizing (40px tall, 40px art)
        local isRow    = (name == "Item(Small)" or name == "Item(Vertical)" or
                          name == "Item(SearchResults)" or name == "Item(NowPlayingQueue)" or
                          name == "Item(Playlist)")
        local isSearch = (name == "Item(SearchResults)")
        local isQueue  = (name == "Item(NowPlayingQueue)")
        local isSmall  = (name == "Item(Small)")
        local isTallRow = (name == "Item(Small)" or name == "Item(Vertical)" or name == "Item(Playlist)")

        -- Root ImageButton
        -- Cards: 120×160, clip children, UICorner+UIScale for hover lift
        -- Rows:  full-width × 40/50, no clip
        local btn = Instance.new("ImageButton")
        btn.Name = name; btn.Parent = Items
        btn.BackgroundTransparency = 1; btn.Visible = true
        btn.BorderSizePixel = 0; btn.AutoButtonColor = false
        -- Fix: rbxmx Item(Big) has ClipsDescendants=false. Setting true causes rectangular
        -- clipping that ignores UICorner, making photo corners appear square when scaled up.
        btn.ClipsDescendants = false
        btn:AddTag("MastersTemplate")

        if isRow then
            -- Sizes mirror RBXMX templates for both desktop and mobile use.
            -- Item(Small): 200×40; Item(Vertical)/Item(Playlist): full-width × 46.
            -- SearchResults and NowPlayingQueue keep the compact 40px row sizing.
            btn.Size = UDim2.new(isSmall and 0 or 1, isSmall and 200 or 0, 0, isSmall and 40 or (isTallRow and 46 or 40))
            local rc = Instance.new("UICorner"); rc.Name = "corner"; rc.Parent = btn
            pcall(function() rc.CornerRadius = UDim.new(0, isTallRow and 8 or 5) end)
            if isTallRow then
                local rowPad = Instance.new("UIPadding"); rowPad.Name = "padding"; rowPad.Parent = btn
                rowPad.PaddingLeft = UDim.new(0, 6)
                rowPad.PaddingRight = UDim.new(0, 6)
            end
            -- rbxmx: Item(Small), Item(Vertical), Item(SearchResults) có UIStroke(Thickness=5,Transparency=1)
            -- dùng cho animation "đang phát" (highlight viền khi bài đang chạy)
            if name ~= "Item(NowPlayingQueue)" and name ~= "Item(Playlist)" then
                local st = Instance.new("UIStroke"); st.Name = "stroke"; st.Parent = btn
                st.Thickness = 5; st.Transparency = 1
                st.Color = Color3.fromRGB(255,255,255)
            end
            -- isQueue: UIScale — hover animation
            if isQueue then
                local qs = Instance.new("UIScale"); qs.Name = "scale"; qs.Scale = 1; qs.Parent = btn
            end
        else
            btn.Size = UDim2.new(0, 120, 0, 160)
            -- UICorner (visual only — does NOT affect clip region since ClipsDescendants=false)
            local bc = Instance.new("UICorner"); bc.Name = "corner"; bc.Parent = btn
            pcall(function() bc.CornerRadius = UDim.new(0, 12) end)
            -- UIScale for whole-card hover lift effect
            local _bsc = Instance.new("UIScale"); _bsc.Name = "scale"; _bsc.Parent = btn
        end

        -- Root UIListLayout
        local btnList = Instance.new("UIListLayout"); btnList.Name = "list"; btnList.Parent = btn
        btnList.SortOrder = Enum.SortOrder.LayoutOrder
        if isRow then
            btnList.FillDirection       = Enum.FillDirection.Horizontal
            btnList.Padding             = UDim.new(0, 10)
            btnList.HorizontalAlignment = Enum.HorizontalAlignment.Left
            btnList.VerticalAlignment   = Enum.VerticalAlignment.Center
        else
            btnList.FillDirection       = Enum.FillDirection.Vertical
            btnList.Padding             = UDim.new(0, 0)
            btnList.HorizontalAlignment = Enum.HorizontalAlignment.Center
            btnList.VerticalAlignment   = Enum.VerticalAlignment.Center
        end

        -- Art frame
        -- Cards: 120×120 | tall/compact rows: 40×40
        local artSz = isRow and 40 or 120
        local art = Instance.new("Frame"); art.Name = "Art"; art.Parent = btn
        art.BackgroundTransparency = 1; art.Visible = true; art.LayoutOrder = 1
        art.Size = UDim2.new(0, artSz, 0, artSz)

        -- Shadow ImageLabel — card items only (not row items)
        if not isRow then
            local shadow = Instance.new("ImageLabel"); shadow.Name = "Shadow"; shadow.Parent = art
            shadow.BackgroundTransparency = 1
            shadow.Image = "rbxassetid://115501621566128"
            shadow.ImageColor3 = Color3.fromRGB(0,0,0); shadow.ImageTransparency = 0.5
            pcall(function()
                shadow.ScaleType = Enum.ScaleType.Slice
                shadow.SliceCenter = Rect.new(300,300,300,300); shadow.SliceScale = 0.15
            end)
            shadow.Size = UDim2.new(0,150,0,150)
            shadow.Position = UDim2.new(0.5,0,0.5,0); shadow.AnchorPoint = Vector2.new(0.5,0.5)
            local shadowScale = Instance.new("UIScale"); shadowScale.Name = "scale"; shadowScale.Parent = shadow
        else
            -- Row items cũng có Art.Shadow — parse từ rbxmx Item(Small)
            -- Size=70×70, center, SliceScale=0.1 (nhỏ hơn card), có UIScale child
            local shadow = Instance.new("ImageLabel"); shadow.Name = "Shadow"; shadow.Parent = art
            shadow.BackgroundTransparency = 1
            shadow.Image = "rbxassetid://115501621566128"
            shadow.ImageColor3 = Color3.fromRGB(0,0,0); shadow.ImageTransparency = 0.5
            pcall(function()
                shadow.ScaleType = Enum.ScaleType.Slice
                shadow.SliceCenter = Rect.new(300,300,300,300); shadow.SliceScale = 0.1
            end)
            shadow.Size = UDim2.new(0,70,0,70)
            shadow.Position = UDim2.new(0.5,0,0.5,0); shadow.AnchorPoint = Vector2.new(0.5,0.5)
            local shadowScale = Instance.new("UIScale"); shadowScale.Name = "scale"; shadowScale.Parent = shadow
        end

        -- Photo ImageLabel — content set by AddSongItem via GetCoverForSong
        local photoCorner = isRow and 8 or 12  -- rbxmx: all row items Photo.corner=8, cards=12
        local photo = Instance.new("ImageLabel"); photo.Name = "Photo"; photo.Parent = art
        buildSongPhoto(photo, photoCorner)

        -- Default grid (playlist collage, four cover images in 2×2)
        local def = Instance.new("Frame"); def.Name = "Default"; def.Parent = photo
        def.BackgroundTransparency = 1; def.Size = UDim2.fromScale(1,1); def.Visible = false
        local grid = Instance.new("UIGridLayout"); grid.Name = "grid"; grid.Parent = def
        pcall(function() grid.CellSize = UDim2.fromScale(0.5,0.5) end)
        for _, cn in ipairs({"CoverA","CoverB","CoverC","CoverD"}) do
            local c = Instance.new("ImageLabel"); c.Name = cn; c.Parent = def
            c.BackgroundTransparency = 1; c.Size = UDim2.fromScale(1,1)
        end

        -- Duration label — Item(Vertical) only
        -- rbxmx: Weight=600(SemiBold), TextSize=11, TextTransparency=0.5,
        --        AutomaticSize=Y, Size=(0,0,1,0), LayoutOrder=3, PaddingRight=10
        if name == "Item(Vertical)" then
            local dur = Instance.new("TextLabel"); dur.Name = "Duration"; dur.Parent = btn
            dur.BackgroundTransparency = 1; dur.Visible = true; dur.Text = "0:00"
            dur.TextColor3 = Color3.fromRGB(255,255,255); dur.TextTransparency = 0.5
            dur.Size = UDim2.new(0, 0, 1, 0)
            pcall(function() dur.AutomaticSize = Enum.AutomaticSize.X end)
            dur.TextSize = 11; dur.LayoutOrder = 3
            dur.TextXAlignment = Enum.TextXAlignment.Right; dur.TextYAlignment = Enum.TextYAlignment.Center
            pcall(function()
                dur.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.SemiBold)
            end)
            local durPad = Instance.new("UIPadding"); durPad.Name = "padding"; durPad.Parent = dur
            durPad.PaddingRight = UDim.new(0, 10)
        end

        -- "More" button — Item(SearchResults) only
        -- rbxmx: ImageButton "More", Size=(0,40,0,40), LayoutOrder=3, Icon=20×20 inside
        if isSearch then
            local more = Instance.new("ImageButton"); more.Name = "More"; more.Parent = btn
            more.BackgroundTransparency = 1; more.AutoButtonColor = false
            more.Size = UDim2.new(0, 40, 0, 40); more.LayoutOrder = 3
            more.Image = ""
            local moreIcon = Instance.new("ImageLabel"); moreIcon.Name = "Icon"; moreIcon.Parent = more
            moreIcon.BackgroundTransparency = 1; moreIcon.Size = UDim2.new(0, 20, 0, 20)
            moreIcon.AnchorPoint = Vector2.new(0.5, 0.5); moreIcon.Position = UDim2.fromScale(0.5, 0.5)
            moreIcon.Image = "rbxassetid://77658034060897"
            local moreScale = Instance.new("UIScale"); moreScale.Name = "scale"; moreScale.Parent = more
        end

        -- "Handle" frame — Item(NowPlayingQueue) only (drag-to-reorder handle)
        -- rbxmx: ImageLabel "Handle", Size=(0,40,0,40), LayoutOrder=3, ImageTransparency=0.5
        if isQueue then
            local handle = Instance.new("ImageLabel"); handle.Name = "Handle"; handle.Parent = btn
            handle.BackgroundTransparency = 1; handle.ImageTransparency = 0.5
            handle.Size = UDim2.new(0, 40, 0, 40); handle.LayoutOrder = 3
            handle.Image = "rbxassetid://6031094678"
        end

        -- Information frame — UIFlexItem fills remaining space (RBXMX exact structure)
        local info = Instance.new("Frame"); info.Name = "Information"; info.Parent = btn
        buildSongInfo(info,
            isRow and 14 or 15,
            isRow and 11 or 12,
            isRow,
            false)
        -- Card items: UIFlexItem có thể không fill height trong executor →
        -- đặt explicit height = btnHeight - artHeight để Center alignment không bị lệch
        -- rbxmx: Item(Big)=160px tall, Art=120px → Info=40px | Item(Shared)=180px, Art=120px → 60px
        if not isRow then
            local infoH = (name == "Item(Big)" and 40) or (name == "Item(Shared)" and 60) or 40
            info.Size = UDim2.new(1, 0, 0, infoH)
        end

        -- Sender frame (Item(Shared) variant, hidden in layout by LayoutOrder=99)
        local sender = Instance.new("Frame"); sender.Name = "Sender"; sender.Parent = btn
        sender.BackgroundTransparency = 1; sender.Visible = false; sender.LayoutOrder = 99
        sender.Size = UDim2.fromScale(1,0)
        local sProfile = Instance.new("ImageLabel"); sProfile.Name = "Profile"; sProfile.Parent = sender; sProfile.BackgroundTransparency = 1
        local sUser = Instance.new("TextLabel"); sUser.Name = "Username"; sUser.Parent = sender; sUser.BackgroundTransparency = 1

        return btn
    end

    buildSongItem("Item(Big)")
    buildSongItem("Item(Small)")
    buildSongItem("Item(Vertical)")
    buildSongItem("Item(SearchResults)")
    buildSongItem("Item(Shared)")
    buildSongItem("Item(Playlist)")
    buildSongItem("Item(NowPlayingQueue)")

    -- ── Station(Big) ── parsed from Masters.rbxmx ────────────────────────
    do
        -- Root: ImageButton, Size=(0,180,0,220), BackgroundTransparency=1
        local btn = Instance.new("ImageButton")
        btn.Name = "Station(Big)"; btn.Parent = Items
        btn.BackgroundTransparency = 1
        btn.Size = UDim2.new(0, 180, 0, 220)
        btn.AutoButtonColor = false
        btn.BorderSizePixel = 0
        btn.LayoutOrder = 1
        btn:AddTag("MastersOnboardingTemplate")

        -- UICorner radius=10
        local rootCorner = Instance.new("UICorner"); rootCorner.Name = "corner"; rootCorner.Parent = btn
        rootCorner.CornerRadius = UDim.new(0, 10)

        -- ── Util (Folder) ──────────────────────────────────────────────────
        local util = Instance.new("Folder"); util.Name = "Util"; util.Parent = btn

        -- Visuals: CanvasGroup, Size=(1,0,1,0), anchor=(0.5,0.5), pos=(0.5,0,0.5,0)
        -- ClipsDescendants=true so Art/Fade are clipped by UICorner
        local visuals = Instance.new("CanvasGroup"); visuals.Name = "Visuals"; visuals.Parent = util
        visuals.BackgroundTransparency = 1
        visuals.ClipsDescendants = true
        visuals.Size = UDim2.fromScale(1, 1)
        visuals.AnchorPoint = Vector2.new(0.5, 0.5)
        visuals.Position = UDim2.fromScale(0.5, 0.5)
        visuals.ZIndex = 0
        local vCorner = Instance.new("UICorner"); vCorner.Name = "corner"; vCorner.Parent = visuals
        vCorner.CornerRadius = UDim.new(0, 10)

        -- Art: ImageLabel, Size=(1,0,1,0), ScaleType=Crop, ZIndex=1
        -- Full background cover image; UIScale scale=1.01 (slight zoom, avoids edge seams)
        local art = Instance.new("ImageLabel"); art.Name = "Art"; art.Parent = visuals
        art.BackgroundTransparency = 1
        art.Size = UDim2.fromScale(1, 1)
        art.Position = UDim2.fromScale(0, 0)
        art.ScaleType = Enum.ScaleType.Crop
        art.Image = "rbxassetid://74118540785733"
        art.ImageColor3 = Color3.fromRGB(255, 255, 255)
        art.ZIndex = 1
        local artScale = Instance.new("UIScale"); artScale.Name = "scale"; artScale.Parent = art
        artScale.Scale = 1.01

        -- Fade: ImageLabel, Size=(0,130,0,130), anchor+pos=(0.5,0.5), ScaleType=Crop, ZIndex=2
        -- UIScale scale=100 blows it up to fill; UIGradient fades bottom half to black
        local fade = Instance.new("ImageLabel"); fade.Name = "Fade"; fade.Parent = visuals
        fade.BackgroundTransparency = 1
        fade.Size = UDim2.new(0, 130, 0, 130)
        fade.AnchorPoint = Vector2.new(0.5, 0.5)
        fade.Position = UDim2.fromScale(0.5, 0.5)
        fade.ScaleType = Enum.ScaleType.Crop
        fade.Image = "rbxassetid://74118540785733"
        fade.ImageColor3 = Color3.fromRGB(100, 100, 100) -- fixed4: tối hơn để gradient rõ hơn
        fade.ZIndex = 2
        local fadeScale = Instance.new("UIScale"); fadeScale.Name = "scale"; fadeScale.Parent = fade
        fadeScale.Scale = 100
        local fadeGrad = Instance.new("UIGradient"); fadeGrad.Name = "gradient"; fadeGrad.Parent = fade
        fadeGrad.Rotation = -90
        pcall(function()
            fadeGrad.Transparency = NumberSequence.new({
                NumberSequenceKeypoint.new(0,    0),
                NumberSequenceKeypoint.new(0.496, 0),
                NumberSequenceKeypoint.new(0.5015, 1),
                NumberSequenceKeypoint.new(1,    1),
            })
        end)

        -- ── Content (Frame overlay) ────────────────────────────────────────
        -- Size=(1,0,1,0), anchor=(0.5,0.5), pos=(0.5,0,0.5,0), ZIndex=1
        -- UIListLayout: Vertical, VerticalAlignment=Bottom, Padding=2
        local content = Instance.new("Frame"); content.Name = "Content"; content.Parent = btn
        content.BackgroundTransparency = 1
        content.Size = UDim2.fromScale(1, 1)
        content.AnchorPoint = Vector2.new(0.5, 0.5)
        content.Position = UDim2.fromScale(0.5, 0.5)
        content.ZIndex = 1

        local cList = Instance.new("UIListLayout"); cList.Name = "list"; cList.Parent = content
        cList.FillDirection = Enum.FillDirection.Vertical
        cList.HorizontalAlignment = Enum.HorizontalAlignment.Left
        cList.VerticalAlignment = Enum.VerticalAlignment.Bottom
        cList.SortOrder = Enum.SortOrder.LayoutOrder
        cList.Padding = UDim.new(0, 2)

        local cPad = Instance.new("UIPadding"); cPad.Name = "padding"; cPad.Parent = content
        cPad.PaddingBottom = UDim.new(0, 10) -- fixed4: 10px uniform
        cPad.PaddingLeft   = UDim.new(0, 10)
        cPad.PaddingRight  = UDim.new(0, 10)
        cPad.PaddingTop    = UDim.new(0, 10)

        -- Title: TextLabel, Size=(1,0,0,14), Weight=600, TextSize=14, TextWrapped=false
        -- UIGradient fades text right edge (TextTruncate alternative)
        local title = Instance.new("TextLabel"); title.Name = "Title"; title.Parent = content
        title.BackgroundTransparency = 1
        title.Size = UDim2.new(1, 0, 0, 14)
        title.TextColor3 = Color3.fromRGB(255, 255, 255)
        title.TextTransparency = 0
        title.TextSize = 14
        title.Text = "Station"
        title.TextWrapped = false
        title.TextXAlignment = Enum.TextXAlignment.Left
        title.TextYAlignment = Enum.TextYAlignment.Top
        title.LayoutOrder = 0
        title.AutoLocalize = false
        pcall(function() title.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.SemiBold) end)
        local tGrad = Instance.new("UIGradient"); tGrad.Name = "gradient"; tGrad.Parent = title
        pcall(function()
            tGrad.Transparency = NumberSequence.new({
                NumberSequenceKeypoint.new(0,    0),
                NumberSequenceKeypoint.new(0.799, 0),
                NumberSequenceKeypoint.new(1,    1),
            })
        end)

        -- Description: TextLabel, Size=(1,0,0,0), AutomaticSize=Y, TextSize=12,
        -- TextTransparency=0.5, TextWrapped=true, Weight=400
        local desc = Instance.new("TextLabel"); desc.Name = "Description"; desc.Parent = content
        desc.BackgroundTransparency = 1
        desc.Size = UDim2.new(1, 0, 0, 0)
        desc.AutomaticSize = Enum.AutomaticSize.Y
        desc.TextColor3 = Color3.fromRGB(255, 255, 255)
        desc.TextTransparency = 0.5
        desc.TextSize = 12
        desc.Text = "Description"
        desc.TextWrapped = true
        desc.TextXAlignment = Enum.TextXAlignment.Left
        desc.TextYAlignment = Enum.TextYAlignment.Top
        desc.LayoutOrder = 0
        desc.AutoLocalize = false
        pcall(function() desc.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Regular) end)

        -- UIScale for press/hover animation (same as Item(Big))
        local bsc = Instance.new("UIScale"); bsc.Name = "scale"; bsc.Parent = btn
        bsc.Scale = 1
    end

    -- ── Artist(Standard / SearchResults / Shared / Card) ─────────────────────────
    local function buildArtistItem(name)
        -- rbxmx: Standard=(0,120,0,150) Shared=(0,120,0,170) Card=(0,120,0,160) SearchResults=(1,0,0,40 row)
        local isCard = (name ~= "Artist(SearchResults)")
        local btn = Instance.new("ImageButton")
        btn.Name = name; btn.Parent = Items
        btn.BackgroundTransparency = 1
        btn:AddTag("MastersTemplate")

        -- Sizes from rbxmx
        if name == "Artist(Standard)" then
            btn.Size = UDim2.new(0, 120, 0, 150)
        elseif name == "Artist(Shared)" then
            btn.Size = UDim2.new(0, 120, 0, 170)
        elseif name == "Artist(Card)" then
            btn.Size = UDim2.new(0, 120, 0, 160)
        else -- Artist(SearchResults): full-width 40px row
            btn.Size = UDim2.new(1, 0, 0, 40)
        end
        if isCard then
            local _bsc = Instance.new("UIScale"); _bsc.Name = "scale"; _bsc.Parent = btn
        end

        btn.ClipsDescendants = false
        local btnList = Instance.new("UIListLayout"); btnList.Name = "list"; btnList.Parent = btn
        btnList.SortOrder = Enum.SortOrder.LayoutOrder

        if isCard then
            -- rbxmx: Vertical card layout, Padding=10 between art and info
            btnList.FillDirection = Enum.FillDirection.Vertical
            btnList.HorizontalAlignment = Enum.HorizontalAlignment.Center
            btnList.VerticalAlignment = Enum.VerticalAlignment.Center
            btnList.Padding = UDim.new(0, 10)
        else
            -- SearchResults: Horizontal row
            btnList.FillDirection = Enum.FillDirection.Horizontal
            btnList.HorizontalAlignment = Enum.HorizontalAlignment.Center
            btnList.VerticalAlignment = Enum.VerticalAlignment.Center
            btnList.Padding = UDim.new(0, 10)
        end

        if isCard then
            local btnPad = Instance.new("UIPadding"); btnPad.Name = "padding"; btnPad.Parent = btn
            pcall(function()
                btnPad.PaddingLeft = UDim.new(0, 0); btnPad.PaddingRight = UDim.new(0, 0)
            end)
        end

        -- Art — card artist types 120x120, SearchResults compact 40x40
        local artSz = isCard and 120 or 40
        local art = Instance.new("Frame"); art.Name = "Art"; art.Parent = btn
        art.BackgroundTransparency = 1
        art.Size = UDim2.new(0, artSz, 0, artSz)
        art.LayoutOrder = 1
        local photo = Instance.new("ImageLabel"); photo.Name = "Photo"; photo.Parent = art
        photo.BackgroundColor3 = Color3.fromRGB(37, 39, 44)
        photo.BackgroundTransparency = 0
        photo.Image = ""
        photo.ScaleType = Enum.ScaleType.Crop
        photo.Size = UDim2.fromScale(1, 1)
        photo.Position = UDim2.fromScale(0.5, 0.5)
        photo.AnchorPoint = Vector2.new(0.5, 0.5)
        pcall(function()
            local c = Instance.new("UICorner"); c.Name = "corner"; c.Parent = photo
            c.CornerRadius = UDim.new(1, 0) -- full circle
        end)
        -- Initials label — rbxmx: TextSize=50/Weight=600 for card circles, 18 for row
        local initials = Instance.new("TextLabel"); initials.Name = "Initials"; initials.Parent = photo
        initials.BackgroundTransparency = 1
        initials.Size = UDim2.fromScale(1, 1)
        initials.TextColor3 = Color3.fromRGB(255, 255, 255)
        initials.TextSize = isCard and 50 or 18; initials.Text = ""
        pcall(function() initials.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Bold) end)
        local grad = Instance.new("UIGradient"); grad.Name = "gradient"; grad.Parent = photo

        -- Hover glow — card types only (rbxmx: Hover > Glow + Inner + Outer)
        if isCard then
            local hover = Instance.new("CanvasGroup"); hover.Name = "Hover"; hover.Parent = photo
            hover.BackgroundTransparency = 1; hover.GroupTransparency = 1
            hover.AnchorPoint = Vector2.new(0.5, 0.5)
            hover.Position = UDim2.new(0.5, 0, 0.5, 0)
            hover.Size = UDim2.new(1, 0, 1, 0)
            pcall(function()
                local hCorner = Instance.new("UICorner"); hCorner.CornerRadius = UDim.new(1,0); hCorner.Parent = hover
            end)
            local glow = Instance.new("Frame"); glow.Name = "Glow"; glow.Parent = hover
            glow.BackgroundTransparency = 1; glow.Size = UDim2.fromScale(0, 0)
            pcall(function() glow:SetAttribute("Enabled", false) end)
            -- rbxmx: Inner=200x200 Transp=0.98 ScaleType=Fit, Outer=300x300 Transp=0.5
            local inner = Instance.new("ImageLabel"); inner.Name = "Inner"; inner.Parent = hover
            inner.BackgroundTransparency = 1
            inner.Image = "rbxassetid://122971705612181"
            inner.ImageTransparency = 0.98
            inner.ScaleType = Enum.ScaleType.Fit
            inner.Size = UDim2.new(0, 200, 0, 200)
            inner.AnchorPoint = Vector2.new(0.5, 0.5)
            inner.Position = UDim2.new(0.5, 0, 0.5, 0)
            local outer = Instance.new("ImageLabel"); outer.Name = "Outer"; outer.Parent = hover
            outer.BackgroundTransparency = 1
            outer.Image = "rbxassetid://122971705612181"
            outer.ImageTransparency = 0.5
            outer.Size = UDim2.new(0, 300, 0, 300)
            outer.AnchorPoint = Vector2.new(0.5, 0.5)
            outer.Position = UDim2.new(0.5, 0, 0.5, 0)
        end

        mk("Frame", "Pinned", photo)
        mkImage("Profile", photo)

        -- Information — rbxmx: explicit heights (total - art - listPad10)
        -- Standard: 150-120-10=20 | Shared: 170-120-10=40 | Card: 160-120-10=30 | SearchResults: flex
        local info = Instance.new("Frame"); info.Name = "Information"; info.Parent = btn
        info.BackgroundTransparency = 1
        if name == "Artist(Standard)" then
            info.Size = UDim2.new(1, 0, 0, 20)
        elseif name == "Artist(Shared)" then
            info.Size = UDim2.new(1, 0, 0, 40)
        elseif name == "Artist(Card)" then
            info.Size = UDim2.new(1, 0, 0, 30)
        else
            info.Size = UDim2.new(0, 0, 1, 0)
        end
        info.LayoutOrder = 2
        pcall(function()
            local fi = Instance.new("UIFlexItem"); fi.Name = "flex"; fi.Parent = info
            fi.FlexMode = Enum.UIFlexMode.Fill
        end)
        local infoList = Instance.new("UIListLayout"); infoList.Name = "list"; infoList.Parent = info
        infoList.FillDirection = Enum.FillDirection.Vertical
        infoList.VerticalAlignment = Enum.VerticalAlignment.Center
        infoList.SortOrder = Enum.SortOrder.LayoutOrder
        infoList.HorizontalAlignment = Enum.HorizontalAlignment.Left
        -- rbxmx: Info UIPadding Left=2, Right=2 for card artist types
        if isCard then
            local infoPad = Instance.new("UIPadding"); infoPad.Name = "padding"; infoPad.Parent = info
            pcall(function()
                infoPad.PaddingLeft = UDim.new(0, 2); infoPad.PaddingRight = UDim.new(0, 2)
            end)
        end

        -- ArtistName — rbxmx: Size=(1,0,0,14), TextSize=15/Weight=Medium(500) for cards
        local artistName = Instance.new("TextLabel"); artistName.Name = "ArtistName"; artistName.Parent = info
        artistName.BackgroundTransparency = 1
        artistName.Size = UDim2.new(1, 0, 0, 14)  -- rbxmx height=14 (not 16)
        artistName.TextColor3 = Color3.fromRGB(255, 255, 255)
        artistName.TextTransparency = 0
        -- rbxmx: Standard/Shared=15, Card=13, SearchResults=14
        artistName.TextSize = (name=="Artist(Card)") and 13 or (name=="Artist(SearchResults)") and 14 or 15
        artistName.Text = ""; artistName.TextTruncate = Enum.TextTruncate.AtEnd
        artistName.TextXAlignment = Enum.TextXAlignment.Left
        -- rbxmx: Weight=500 (Medium) for Standard/Shared; SemiBold for Card; Medium for SearchResults
        pcall(function()
            local w = (name == "Artist(Card)") and Enum.FontWeight.SemiBold or Enum.FontWeight.Medium
            artistName.FontFace = Font.new("rbxassetid://12187365364", w)
        end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = artistName
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)

        -- Title sub-label (role description "Artist")
        local titleLbl = Instance.new("TextLabel"); titleLbl.Name = "Title"; titleLbl.Parent = info
        titleLbl.BackgroundTransparency = 1
        titleLbl.Size = UDim2.new(1, 0, 0, 14)
        titleLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
        titleLbl.TextTransparency = 0.5
        titleLbl.TextSize = 12; titleLbl.Text = "Artist"
        titleLbl.TextTruncate = Enum.TextTruncate.AtEnd
        titleLbl.TextXAlignment = Enum.TextXAlignment.Left
        pcall(function() titleLbl.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Regular) end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = titleLbl
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)

        -- "More" chevron button — Artist(SearchResults) only
        -- rbxmx: ImageButton "More", Size=(0,?,0,?) > ImageLabel "Icon" 14x14, Image=rbxassetid://11419703997, LayoutOrder=3
        if name == "Artist(SearchResults)" then
            local more = Instance.new("ImageButton"); more.Name = "More"; more.Parent = btn
            more.BackgroundTransparency = 1; more.AutoButtonColor = false
            more.Size = UDim2.new(0, 40, 0, 40); more.LayoutOrder = 3
            more.Image = ""
            local moreIcon = Instance.new("ImageLabel"); moreIcon.Name = "Icon"; moreIcon.Parent = more
            moreIcon.BackgroundTransparency = 1; moreIcon.Size = UDim2.new(0, 14, 0, 14)
            moreIcon.AnchorPoint = Vector2.new(0.5, 0.5); moreIcon.Position = UDim2.fromScale(0.5, 0.5)
            moreIcon.Image = "rbxassetid://11419703997"
            local moreScale = Instance.new("UIScale"); moreScale.Name = "scale"; moreScale.Parent = more
        end

        -- Sender frame: Artist(Shared) only
        if name == "Artist(Shared)" then
            local sender = Instance.new("Frame"); sender.Name = "Sender"; sender.Parent = btn
            sender.BackgroundTransparency = 1; sender.Visible = false; sender.LayoutOrder = 99
            sender.Size = UDim2.fromScale(1, 0)
            local sProfile = Instance.new("ImageLabel"); sProfile.Name = "Profile"; sProfile.Parent = sender; sProfile.BackgroundTransparency = 1
            local sUser = Instance.new("TextLabel"); sUser.Name = "Username"; sUser.Parent = sender; sUser.BackgroundTransparency = 1
        end

        return btn
    end
    buildArtistItem("Artist(Standard)")
    buildArtistItem("Artist(SearchResults)")
    buildArtistItem("Artist(Shared)")
    buildArtistItem("Artist(Card)")

    -- ── Playlist(Big / Shared / Card) ────────────────────────────────────────────
    local function buildPlaylistItem(name)
        -- rbxmx: ALL playlist types are vertical cards (no horizontal row variant)
        -- Big=(0,120,0,160), Shared=(0,120,0,180), Card=(0,120,0,160)
        local isCard = true  -- all three are cards
        local btn = Instance.new("ImageButton")
        btn.Name = name; btn.Parent = Items
        btn.BackgroundTransparency = 1
        btn:AddTag("MastersTemplate")
        
        if name == "Playlist(Shared)" then
            btn.Size = UDim2.new(0, 120, 0, 180)
        else  -- Playlist(Big) and Playlist(Card) both 120×160
            btn.Size = UDim2.new(0, 120, 0, 160)
        end
        local _bsc = Instance.new("UIScale"); _bsc.Name = "scale"; _bsc.Parent = btn
        
        btn.ClipsDescendants = false
        local btnList = Instance.new("UIListLayout"); btnList.Name = "list"; btnList.Parent = btn
        btnList.SortOrder = Enum.SortOrder.LayoutOrder
        -- rbxmx: Vertical card layout, Padding=10
        btnList.FillDirection = Enum.FillDirection.Vertical
        btnList.HorizontalAlignment = Enum.HorizontalAlignment.Center
        btnList.VerticalAlignment = Enum.VerticalAlignment.Center
        btnList.Padding = UDim.new(0, 10)
        
        local btnPad = Instance.new("UIPadding"); btnPad.Name = "padding"; btnPad.Parent = btn
        pcall(function() 
            btnPad.PaddingLeft = UDim.new(0, 0); btnPad.PaddingRight = UDim.new(0, 0)
        end)

        -- Art — rbxmx: all playlist types use 120×120 art
        local artSz = 120
        local art = Instance.new("Frame"); art.Name = "Art"; art.Parent = btn
        art.BackgroundTransparency = 1
        art.Size = UDim2.new(0, artSz, 0, artSz)
        art.LayoutOrder = 1
        
        -- Shadow (all playlist types are cards)
        do
            local shadow = Instance.new("ImageLabel"); shadow.Name = "Shadow"; shadow.Parent = art
            shadow.BackgroundTransparency = 1
            shadow.Image = "rbxassetid://115501621566128"
            shadow.ImageColor3 = Color3.fromRGB(0,0,0); shadow.ImageTransparency = 0.5
            pcall(function()
                shadow.ScaleType = Enum.ScaleType.Slice
                shadow.SliceCenter = Rect.new(300,300,300,300); shadow.SliceScale = 0.15
            end)
            shadow.Size = UDim2.new(0,150,0,150)
            shadow.Position = UDim2.new(0.5,0,0.5,0); shadow.AnchorPoint = Vector2.new(0.5,0.5)
            local shadowScale = Instance.new("UIScale"); shadowScale.Name = "scale"; shadowScale.Parent = shadow
        end

        -- Photo (using CanvasGroup to allow UICorner clipping for collage)
        local photo = Instance.new("CanvasGroup"); photo.Name = "Photo"; photo.Parent = art
        photo.BackgroundColor3 = Color3.fromRGB(37, 39, 44)
        photo.BackgroundTransparency = 0
        photo.Size = UDim2.fromScale(1, 1)
        photo.Position = UDim2.fromScale(0.5, 0.5)
        photo.AnchorPoint = Vector2.new(0.5, 0.5)
        photo.GroupTransparency = 0
        photo.BorderSizePixel = 0
        -- rbxmx: Art.Photo (CanvasGroup) has UIScale "scale" child for hover zoom tween
        local photoScale = Instance.new("UIScale"); photoScale.Name = "scale"; photoScale.Scale = 1; photoScale.Parent = photo
        pcall(function()
            local c = Instance.new("UICorner"); c.Name = "corner"; c.Parent = photo
            c.CornerRadius = UDim.new(0, 12)
        end)
        
        -- Hover (all playlist types are cards)
        do
            local hover = Instance.new("CanvasGroup"); hover.Name = "Hover"; hover.Parent = photo
            hover.BackgroundTransparency = 1; hover.GroupTransparency = 1
            hover.AnchorPoint = Vector2.new(0.5,0.5); hover.Position = UDim2.new(0.5,0,0.5,0); hover.Size = UDim2.new(1,0,1,0)
            local glow = Instance.new("Frame"); glow.Name = "Glow"; glow.Parent = hover
            glow.BackgroundTransparency = 1; glow.Size = UDim2.fromScale(0,0)
            pcall(function() glow:SetAttribute("Enabled", false) end)
            -- rbxmx: Hover > Inner(200×200, Transp=0.98) + Outer(300×300, Transp=0.5)
            local pInner = Instance.new("ImageLabel"); pInner.Name = "Inner"; pInner.Parent = hover
            pInner.BackgroundTransparency = 1
            pInner.Image = "rbxassetid://122971705612181"
            pInner.ImageTransparency = 0.98
            pInner.ScaleType = Enum.ScaleType.Fit
            pInner.Size = UDim2.new(0, 200, 0, 200)
            pInner.AnchorPoint = Vector2.new(0.5, 0.5)
            pInner.Position = UDim2.new(0.5, 0, 0.5, 0)
            local pOuter = Instance.new("ImageLabel"); pOuter.Name = "Outer"; pOuter.Parent = hover
            pOuter.BackgroundTransparency = 1
            pOuter.Image = "rbxassetid://122971705612181"
            pOuter.ImageTransparency = 0.5
            pOuter.Size = UDim2.new(0, 300, 0, 300)
            pOuter.AnchorPoint = Vector2.new(0.5, 0.5)
            pOuter.Position = UDim2.new(0.5, 0, 0.5, 0)
        end
        
        -- Main Image (for single cover case)
        local mainImg = Instance.new("ImageLabel"); mainImg.Name = "MainImage"; mainImg.Parent = photo
        mainImg.BackgroundTransparency = 1
        mainImg.Size = UDim2.fromScale(1, 1)
        mainImg.ScaleType = Enum.ScaleType.Crop
        mainImg.Visible = true

        mk("Frame", "Pinned", photo)
        -- Default collage
        local def = Instance.new("Frame"); def.Name = "Default"; def.Parent = photo
        def.BackgroundTransparency = 1
        def.Size = UDim2.fromScale(1, 1)
        def.Visible = false
        def.ClipsDescendants = true
        local grid = Instance.new("UIGridLayout"); grid.Name = "grid"; grid.Parent = def
        pcall(function() grid.CellSize = UDim2.fromScale(0.5, 0.5) grid.CellPadding = UDim2.new(0,0,0,0) end)
        for _, cn in ipairs({"CoverA","CoverB","CoverC","CoverD"}) do
            local c = Instance.new("ImageLabel"); c.Name = cn; c.Parent = def
            c.BackgroundTransparency = 1
            c.Size = UDim2.fromScale(1, 1)
            c.ScaleType = Enum.ScaleType.Crop
        end

        -- Information — rbxmx explicit heights (total - art120 - listPadding10)
        -- Big/Card=30px, Shared=50px
        local info = Instance.new("Frame"); info.Name = "Information"; info.Parent = btn
        info.BackgroundTransparency = 1
        if name == "Playlist(Shared)" then
            info.Size = UDim2.new(1, 0, 0, 50)
        else  -- Big and Card
            info.Size = UDim2.new(1, 0, 0, 30)
        end
        info.LayoutOrder = 2
        pcall(function()
            local fi = Instance.new("UIFlexItem"); fi.Name = "flex"; fi.Parent = info
            fi.FlexMode = Enum.UIFlexMode.Fill
        end)
        local infoList = Instance.new("UIListLayout"); infoList.Name = "list"; infoList.Parent = info
        infoList.FillDirection = Enum.FillDirection.Vertical
        infoList.VerticalAlignment = Enum.VerticalAlignment.Center
        infoList.SortOrder = Enum.SortOrder.LayoutOrder
        infoList.HorizontalAlignment = Enum.HorizontalAlignment.Left
        -- rbxmx: Info list Padding=5 for Big/Shared (spacing between Title and Source)
        if name ~= "Playlist(Card)" then
            infoList.Padding = UDim.new(0, 5)
        end
        -- rbxmx: Info UIPadding Left=2, Right=2
        local infoPad = Instance.new("UIPadding"); infoPad.Name = "padding"; infoPad.Parent = info
        pcall(function()
            infoPad.PaddingLeft = UDim.new(0, 2); infoPad.PaddingRight = UDim.new(0, 2)
        end)
        
        -- Title — rbxmx: TextSize=15/Weight=500 for Big/Shared, 13/SemiBold for Card
        local titleLbl = Instance.new("TextLabel"); titleLbl.Name = "Title"; titleLbl.Parent = info
        titleLbl.BackgroundTransparency = 1
        titleLbl.Size = UDim2.new(1, 0, 0, 14)  -- rbxmx: height=14 (YO=14)
        titleLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
        titleLbl.TextTransparency = 0
        titleLbl.TextSize = (name == "Playlist(Card)") and 13 or 15  -- rbxmx: Big/Shared=15
        titleLbl.Text = ""
        titleLbl.TextTruncate = Enum.TextTruncate.AtEnd
        titleLbl.TextXAlignment = Enum.TextXAlignment.Left
        pcall(function()
            local w = (name == "Playlist(Card)") and Enum.FontWeight.SemiBold or Enum.FontWeight.Medium
            titleLbl.FontFace = Font.new("rbxassetid://12187365364", w)
        end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = titleLbl
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)
        
        local sourceLbl = Instance.new("TextLabel"); sourceLbl.Name = "Source"; sourceLbl.Parent = info
        sourceLbl.BackgroundTransparency = 1
        sourceLbl.Size = UDim2.new(1, 0, 0, 12)
        sourceLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
        sourceLbl.TextTransparency = 0.5
        sourceLbl.TextSize = 12; sourceLbl.Text = ""
        sourceLbl.TextTruncate = Enum.TextTruncate.AtEnd
        sourceLbl.TextXAlignment = Enum.TextXAlignment.Left
        pcall(function() sourceLbl.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Regular) end)
        pcall(function()
            local g = Instance.new("UIGradient"); g.Name = "gradient"; g.Parent = sourceLbl
            g.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0), NumberSequenceKeypoint.new(0.8,0), NumberSequenceKeypoint.new(1,1)})
        end)

        local sender = mk("Frame", "Sender", btn)
        mkImage("Profile", sender); mkLabel("Username", sender)
        return btn
    end
    buildPlaylistItem("Playlist(Big)")
    buildPlaylistItem("Playlist(Shared)")
    buildPlaylistItem("Playlist(Card)")

    -- ── Containers ────────────────────────────────────────────────────────
    local function buildContainer(name, contentHeight)
        -- contentHeight: height of Content SF (default 160px). Container(Stations) uses 220 for Station(Big) cards (180x220).
        contentHeight = contentHeight or 160
        local f = Instance.new("Frame")
        f.Name = name; f.Parent = Items
        pcall(function()
            f.BackgroundTransparency = 1
            f.Size = UDim2.new(1, 0, 0, contentHeight + 40) -- +40: 30 header + 10 list padding
            f.ClipsDescendants = false
        end)
        f:AddTag("MastersTemplate")
        f:AddTag("MastersHorizontalContainer")

        -- Root layout: vertical, Padding=10, LayoutOrder sort (matches XML)
        local rootList = Instance.new("UIListLayout"); rootList.Name="list"; rootList.Parent=f
        pcall(function()
            rootList.FillDirection = Enum.FillDirection.Vertical
            rootList.SortOrder = Enum.SortOrder.LayoutOrder
            rootList.Padding = UDim.new(0,10)
            rootList.HorizontalAlignment = Enum.HorizontalAlignment.Center
        end)

        -- Header: ImageButton (matches real XML), Size=(1,0,0,30), LayoutOrder=1
        local hdr = Instance.new("ImageButton"); hdr.Name="Header"; hdr.Parent=f
        pcall(function()
            hdr.BackgroundTransparency = 1
            hdr.Size = UDim2.new(1,0,0,30)
            hdr.LayoutOrder = 1
            hdr.AutoButtonColor = false
            hdr.BorderSizePixel = 0
        end)

        -- Header interior: horizontal UIListLayout (Padding=2, Wraps=true, HorizontalAlignment=Center)
        local hdrList = Instance.new("UIListLayout"); hdrList.Name="list"; hdrList.Parent=hdr
        pcall(function()
            hdrList.FillDirection = Enum.FillDirection.Horizontal
            hdrList.HorizontalAlignment = Enum.HorizontalAlignment.Left
            hdrList.VerticalAlignment = Enum.VerticalAlignment.Center
            hdrList.SortOrder = Enum.SortOrder.LayoutOrder
            hdrList.Padding = UDim.new(0,2)
            hdrList.Wraps = false
        end)

        -- Spacer fills remaining header space after Label
        local spacer = Instance.new("Frame"); spacer.Name="Spacer"; spacer.Parent=hdr
        pcall(function()
            spacer.BackgroundTransparency=1; spacer.LayoutOrder=5
            spacer.Size=UDim2.new(1,0,1,0)
        end)
        local spacerFlex = Instance.new("UIFlexItem"); spacerFlex.Name="flex"; spacerFlex.Parent=spacer
        pcall(function() spacerFlex.FlexMode=Enum.UIFlexMode.Fill end)

        -- Label: sitting left-most
        local lbl = Instance.new("TextLabel"); lbl.Name="Label"; lbl.Parent=hdr
        pcall(function()
            lbl.BackgroundTransparency = 1
            lbl.Text = ""
            lbl.Size = UDim2.new(0,0,0,15)  -- rbxmx: height=15 (not 18)
            lbl.AutomaticSize = Enum.AutomaticSize.X
            lbl.LayoutOrder = 0
            lbl.TextColor3 = Color3.fromRGB(255, 255, 255)
            lbl.TextXAlignment = Enum.TextXAlignment.Left
            lbl.TextSize = 18
            lbl.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.SemiBold)  -- rbxmx: Weight=600 (SemiBold, not Bold/700)
            lbl.TextTruncate = Enum.TextTruncate.None
        end)

        -- Content: ScrollingFrame, LayoutOrder=2, horizontal items
        local contentSF = Instance.new("ScrollingFrame"); contentSF.Name="Content"; contentSF.Parent=f
        pcall(function()
            contentSF.BackgroundTransparency = 1
            contentSF.LayoutOrder = 2
            contentSF.Size = UDim2.new(1,0,0,contentHeight)
            contentSF.CanvasSize = UDim2.new(0,0,0,0)
            contentSF.AutomaticCanvasSize = Enum.AutomaticSize.X
            contentSF.ScrollBarThickness = 0
            contentSF.ScrollingDirection = Enum.ScrollingDirection.X
            contentSF.BorderSizePixel = 0
            contentSF.ClipsDescendants = false -- Fix: allow card scaling without clipping
        end)
        local sfList = Instance.new("UIListLayout"); sfList.Name="list"; sfList.Parent=contentSF
        pcall(function()
            sfList.FillDirection = Enum.FillDirection.Horizontal
            sfList.SortOrder = Enum.SortOrder.LayoutOrder
            sfList.VerticalAlignment = Enum.VerticalAlignment.Top
            sfList.Padding = UDim.new(0,8)
        end)

        -- ── Util > Navigation overlay (parsed from rbxmx) ─────────────────
        -- Navigation sits over the card area: AnchorPoint=(0.5,1), Pos=(0.5,0,1,0),
        -- Size=(1,0,1,-30) = full width, full height minus 30px header, anchored at bottom.
        local util = Instance.new("Folder"); util.Name = "Util"; util.Parent = f

        local nav = Instance.new("Frame"); nav.Name = "Navigation"; nav.Parent = util
        pcall(function()
            nav.BackgroundTransparency = 1
            nav.AnchorPoint = Vector2.new(0.5, 1)
            nav.Position = UDim2.new(0.5, 0, 1, 0)
            nav.Size = UDim2.new(1, 0, 1, -30)
            nav.BorderSizePixel = 0
            nav.ZIndex = 5
        end)

        -- Helper: build Left or Right nav button panel
        local function buildNavSide(sideName, iconId, anchorX, posX)
            local side = Instance.new("Frame"); side.Name = sideName; side.Parent = nav
            pcall(function()
                side.BackgroundTransparency = 1
                side.AnchorPoint = Vector2.new(anchorX, 0)
                side.Position = UDim2.new(posX, 0, 0, 0)
                side.Size = UDim2.new(0, 30, 1, 0)
                side.BorderSizePixel = 0
                side.ZIndex = 5
            end)

            -- Button: ImageButton 30x30, centered
            -- Image rbxassetid://122971705612181 = transparent circular hit area (from rbxmx)
            local btn = Instance.new("ImageButton"); btn.Name = "Button"; btn.Parent = side
            pcall(function()
                btn.Image = "rbxassetid://122971705612181"
                btn.ImageColor3 = Color3.fromRGB(0, 0, 0)
                btn.ImageTransparency = 0.8
                btn.BackgroundTransparency = 1
                btn.AutoButtonColor = false
                btn.AnchorPoint = Vector2.new(0.5, 0.5)
                btn.Position = UDim2.new(0.5, 0, 0.5, 0)
                btn.Size = UDim2.new(0, 30, 0, 30)
                btn.Active = true
                btn.Selectable = true
                btn.BorderSizePixel = 0
                btn.ZIndex = 5
                pcall(function() btn:AddTag("MastersMiniplayerAction") end)
            end)

            -- Background: black circle, BackgroundTransparency=0.9 (rbxmx: 0.899...)
            local bg = Instance.new("Frame"); bg.Name = "Background"; bg.Parent = btn
            pcall(function()
                bg.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
                bg.BackgroundTransparency = 0.9
                bg.AnchorPoint = Vector2.new(0.5, 0.5)
                bg.Position = UDim2.new(0.5, 0, 0.5, 0)
                bg.Size = UDim2.new(0, 38, 0, 38)
                bg.BorderSizePixel = 0
                bg.ZIndex = 0
                local bgCorner = Instance.new("UICorner"); bgCorner.Name = "corner"; bgCorner.Parent = bg
                bgCorner.CornerRadius = UDim.new(1, 0) -- full circle
                local bgScale = Instance.new("UIScale"); bgScale.Name = "scale"; bgScale.Parent = bg
                bgScale.Scale = 1
            end)

            -- Icon: arrow ImageLabel 16x16, centered
            -- Left = rbxassetid://11293981980, Right = rbxassetid://11419703997 (from rbxmx)
            local icon = Instance.new("ImageLabel"); icon.Name = "Icon"; icon.Parent = btn
            pcall(function()
                icon.Image = "rbxassetid://" .. iconId
                icon.ImageColor3 = Color3.fromRGB(255, 255, 255)
                icon.ImageTransparency = 0
                icon.BackgroundTransparency = 1
                icon.AnchorPoint = Vector2.new(0.5, 0.5)
                icon.Position = UDim2.new(0.5, 0, 0.5, 0)
                icon.Size = UDim2.new(0, 16, 0, 16)
                icon.ZIndex = 1
                local iconScale = Instance.new("UIScale"); iconScale.Name = "scale"; iconScale.Parent = icon
                iconScale.Scale = 1
            end)

            -- Selection: highlight ring 38x38, transparent (hover state)
            local sel = Instance.new("Frame"); sel.Name = "Selection"; sel.Parent = btn
            pcall(function()
                sel.BackgroundTransparency = 1
                sel.AnchorPoint = Vector2.new(0.5, 0.5)
                sel.Position = UDim2.new(0.5, 0, 0.5, 0)
                sel.Size = UDim2.new(0, 38, 0, 38)
                sel.ZIndex = 1
                local selCorner = Instance.new("UICorner"); selCorner.Name = "corner"; selCorner.Parent = sel
                selCorner.CornerRadius = UDim.new(1, 0)
                local selScale = Instance.new("UIScale"); selScale.Name = "scale"; selScale.Parent = sel
                selScale.Scale = 1
            end)
        end

        buildNavSide("Left",  "11293981980", 0, 0) -- left arrow icon
        buildNavSide("Right", "11419703997", 1, 1) -- right arrow icon

        return f
    end
    buildContainer("Container(Standard)")
    buildContainer("Container(Stations)", 220) -- Station(Big) cards are 220px tall
    buildContainer("Container(ArtistStandard)")
    buildContainer("Container(Charts)")
    buildContainer("Container(Shared)") -- Fix: was missing, caused crash in Search/Library shared sections

    -- ── Misc utility templates ─────────────────────────────────────────────
