            f.BackgroundTransparency = 1
            f.AutoButtonColor = false
            f.Selectable = false
        end)
        local list = Instance.new("UIListLayout"); list.Name = "list"; list.Parent = f
        pcall(function()
            list.FillDirection = Enum.FillDirection.Vertical
            list.SortOrder = Enum.SortOrder.LayoutOrder
            list.Padding = UDim.new(0, 5)
            list.HorizontalAlignment = Enum.HorizontalAlignment.Center
            list.VerticalAlignment = Enum.VerticalAlignment.Center
        end)
        local usernameLbl = Instance.new("TextLabel"); usernameLbl.Name = "Username"; usernameLbl.Parent = f
        pcall(function()
            usernameLbl.Size = UDim2.new(1, 0, 0, 0)
            usernameLbl.AutomaticSize = Enum.AutomaticSize.Y
            usernameLbl.BackgroundTransparency = 1
            usernameLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
            usernameLbl.TextTransparency = 0
            usernameLbl.TextSize = 9
            usernameLbl.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.Regular, Enum.FontStyle.Normal)
            usernameLbl.TextXAlignment = Enum.TextXAlignment.Center
            usernameLbl.TextTruncate = Enum.TextTruncate.AtEnd
            usernameLbl.LayoutOrder = 2
        end)
        local photo = Instance.new("ImageLabel"); photo.Name = "Photo"; photo.Parent = f
        pcall(function()
            photo.Size = UDim2.fromOffset(40, 40)
            photo.LayoutOrder = 1
            photo.BackgroundColor3 = Color3.fromRGB(30, 30, 30)
            photo.BackgroundTransparency = 0
            photo.ScaleType = Enum.ScaleType.Crop
            local corner = Instance.new("UICorner"); corner.Name = "corner"
            corner.CornerRadius = UDim.new(1, 0); corner.Parent = photo
            local ingame = Instance.new("ImageLabel"); ingame.Name = "Ingame"
            ingame.Size = UDim2.fromOffset(14, 14)
            ingame.Position = UDim2.new(1, 0, 1, 0)
            ingame.AnchorPoint = Vector2.new(0.8, 0.8)
            ingame.BackgroundColor3 = Color3.fromRGB(20, 20, 20)
            ingame.BackgroundTransparency = 0
            ingame.BorderSizePixel = 0
            ingame.Visible = false
            ingame.Parent = photo
            local ingameCorner = Instance.new("UICorner"); ingameCorner.Name = "corner"
            ingameCorner.CornerRadius = UDim.new(1, 0); ingameCorner.Parent = ingame
            local ingameStroke = Instance.new("UIStroke"); ingameStroke.Name = "stroke"
            ingameStroke.Thickness = 2
            ingameStroke.Color = Color3.fromRGB(20, 20, 20)
            ingameStroke.Parent = ingame
        end)
    end
    do
        -- ShareSheetPlayerList (from rbxmx)
        local f = buildMisc("ShareSheetPlayerList", "ImageButton")
        pcall(function()
            f:AddTag("MastersTemplate")
            f.Size = UDim2.new(1, 0, 0, 40)
            f.BackgroundColor3 = Color3.fromRGB(20, 20, 20)
            f.BackgroundTransparency = 0
            f.AutoButtonColor = true
            f.Selectable = true
        end)
        local stroke = Instance.new("UIStroke"); stroke.Name = "stroke"; stroke.Parent = f
        pcall(function()
            stroke.Color = Color3.fromRGB(24, 24, 24)
        end)
        local list = Instance.new("UIListLayout"); list.Name = "list"; list.Parent = f
        pcall(function()
            list.FillDirection = Enum.FillDirection.Horizontal
            list.SortOrder = Enum.SortOrder.LayoutOrder
            list.Padding = UDim.new(0, 8)
            list.VerticalAlignment = Enum.VerticalAlignment.Center
        end)
        local pad = Instance.new("UIPadding"); pad.Name = "padding"; pad.Parent = f
        pcall(function()
            pad.PaddingLeft  = UDim.new(0, 15)
            pad.PaddingRight = UDim.new(0, 15)
        end)
        local photo = Instance.new("ImageLabel"); photo.Name = "Photo"; photo.Parent = f
        pcall(function()
