        local displayLbl = Instance.new("TextLabel"); displayLbl.Name = "Display"; displayLbl.Parent = f
        pcall(function()
            displayLbl.Size = UDim2.new(0, 0, 1, 0)
            displayLbl.AutomaticSize = Enum.AutomaticSize.X
