            displayLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
            displayLbl.TextTransparency = 0
            displayLbl.TextSize = 11
            displayLbl.FontFace = Font.new("rbxassetid://12187365364", Enum.FontWeight.SemiBold, Enum.FontStyle.Normal)
