            displayLbl.TextTruncate = Enum.TextTruncate.None
            local dPad = Instance.new("UIPadding"); dPad.Name = "padding"; dPad.Parent = displayLbl
            dPad.PaddingLeft = UDim.new(0, 5)
        end)
        local usernameLbl = Instance.new("TextLabel"); usernameLbl.Name = "Username"; usernameLbl.Parent = f
        pcall(function()
            usernameLbl.Size = UDim2.new(0, 0, 1, 0)
            usernameLbl.AutomaticSize = Enum.AutomaticSize.None
            usernameLbl.BackgroundTransparency = 1
            usernameLbl.TextColor3 = Color3.fromRGB(255, 255, 255)
            usernameLbl.TextTransparency = 0.5
            usernameLbl.TextSize = 11
