_mc['LyricsEngine'] = loadMod('LyricsEngine', [[
local RunService = game:GetService("RunService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local storage = ReplicatedStorage:WaitForChild("Masters(Storage)")
local events = storage.Events

local CachedLyrics = {}

local module = {}

function module.HasLyrics(SongId, HasIndex)
        local LyricsIndex
        
        if HasIndex then
                LyricsIndex = HasIndex
        else
                LyricsIndex = events.Modules.LyricsEngine.GetLyricsIndex:InvokeServer()
        end
        
        if not LyricsIndex then return end
        
        if LyricsIndex[SongId] or LyricsIndex[tostring(SongId)] then
                return true
        else
                return false
        end
end

function module.GetLyrics(SongId)
        local LyricsIndex = events.Modules.LyricsEngine.GetLyricsIndex:InvokeServer()
        
        if not LyricsIndex then return end
        if not module.HasLyrics(SongId, LyricsIndex) then return end
        
        local Cached

        for i, Data in CachedLyrics do
                if Data.SoundId == SongId then
                        Cached = Data
                end
        end

        if Cached then
                return Cached
        end

        local Data = events.Modules.LyricsEngine.GetLyrics:InvokeServer(LyricsIndex[tostring(SongId)])
        if not Data then return end

        if #CachedLyrics == 30 then
                table.remove(CachedLyrics, 1)
        end 

        table.insert(CachedLyrics, Data)

        return Data
end

return module
]])

_mc['OnlineStations'] = loadMod('OnlineStations', [[
local RunService = game:GetService("RunService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local storage = ReplicatedStorage:WaitForChild("Masters(Storage)")
local events = storage.Events

local module = {}

-- [FIX] Client-side cache: chỉ InvokeServer 1 lần, các lần sau dùng cache
local _cachedStationsIndex = nil

function module.GetOnlineStations()
        if RunService:IsServer() then
                local StationsIndex = events.Modules.OnlineStations.GetStations:Invoke()
                if not StationsIndex then return end
                return StationsIndex

        elseif RunService:IsClient() then
                -- Trả cache nếu đã có
                if _cachedStationsIndex then
                        return _cachedStationsIndex
                end

                local StationsIndex = events.Modules.OnlineStations.GetStationsIndex:InvokeServer()
                if not StationsIndex or not next(StationsIndex) then return end  -- [FIX] không cache kết quả rỗng

                _cachedStationsIndex = StationsIndex   -- lưu cache (chỉ khi có data thật)
                return _cachedStationsIndex
        end
end

function module.GetOnlineStationByStationId(StationId)
        local StationsIndex = module.GetOnlineStations()
        if not StationsIndex then return end
        return StationsIndex[StationId]
end

-- Gọi khi cần force-refresh (vd: sau khi tạo/xoá station)
function module.InvalidateCache()
        _cachedStationsIndex = nil
end

return module
]])

_mc['TextFiltering'] = loadMod('TextFiltering', [[
local RunService = game:GetService("RunService")
local TextService = game:GetService("TextService")

local ReplicatedStorage = game:GetService("ReplicatedStorage")

local storage = ReplicatedStorage:WaitForChild("Masters(Storage)")
local events = storage.Events

local module = {}

local function mask(text)
        return string.rep("#", #text)
end

local function filterForPlayer(text, fromUserId, toPlayer)
        local success, result = pcall(function()
                local filterResult = TextService:FilterStringAsync(text, fromUserId)
                return filterResult:GetChatForUserAsync(toPlayer.UserId)
        end)

        if success and result then
                return result
        else
                warn("Filter failed:", result)
                return mask(text)
        end
end

local function filterBroadcast(text, fromUserId)
        local success, result = pcall(function()
                local filterResult = TextService:FilterStringAsync(text, fromUserId)
                return filterResult:GetNonChatStringForBroadcastAsync()
        end)

        if success and result then
                return result
        else
                warn("Filter failed:", result)
                return mask(text)
        end
end

-- Functions

function module.FilterForPlayer(text, fromUserId, toPlayer)
        if RunService:IsServer() then
                return filterForPlayer(text, fromUserId, toPlayer)
                
        elseif RunService:IsClient() then
                
                local success, result = pcall(function()
                        return events.Modules.TextFiltering.FilterText:InvokeServer("Player", text, toPlayer.UserId)
                end)

                if success and result then
                        return result
                else
                        warn("Remote failed:", result)
                        return mask(text)
                end
        end
end

function module.FilterBroadcast(text, fromUserId)
        if RunService:IsServer() then
                return filterBroadcast(text, fromUserId)
                
        elseif RunService:IsClient() then
                
                local success, result = pcall(function()
                        return events.Modules.TextFiltering.FilterText:InvokeServer("Broadcast", text)
                end)

                if success and result then
                        return result
                else
                        warn("Remote failed:", result)
                        return mask(text)
                end
        end
end

return module
]])

