                        Full.Container.Stations.Canvas.Details.Info.Subtext.Text = 
                                `{#Data.Songs} Song · {Utilities.FormatSecondsToHM(Duration, true)} · Updated {UpData.Relative}`
                end
        end

        Full.Container.Stations.Util.Loading.Visible = false
