                TweenService:Create(MiniplayerPlaybackAnimations.Rewind.Triangles.C, bounce, {ImageTransparency = 0}):Play()
                TweenService:Create(MiniplayerPlaybackAnimations.Rewind.Triangles.C.scale, bounce, {Scale = 1}):Play()

