            TweenService:Create(dialog, normal, {Position = UDim2.new(0.5, 0, 0.5, 0)}):Play()
            TweenService:Create(sheet, TweenInfo.new(0.30, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0.45}):Play()
        end

