            TweenService:Create(sheet, TweenInfo.new(0.22, Enum.EasingStyle.Exponential), {BackgroundTransparency = 1}):Play()
            local tween = TweenService:Create(dialog, normal, {Position = UDim2.new(0.5, 0, 0.5, 24)})
            tween:Play()
            tween.Completed:Connect(function()
                dialog.Visible = false
                dialog.Position = UDim2.new(0.5, 0, 0.5, 0)
                pcall(function() root:Destroy() end)
                pcall(function() sheet:Destroy() end)
                if proceed then
                    task.spawn(function()
                        local songIds = {songId}
                        if hasContinuePlaying and keepCPChecked then
                            for _, item in ipairs(cpList) do
                                if item.Id then table.insert(songIds, item.Id) end
                            end
                        end
                        Queue.LoadSource(songIds, 1, "Saved Session", true)
                        local _waited = 0
                        repeat
                            task.wait(0.25)
                            _waited += 0.25
                        until (Queue.GetActiveSound() and not Queue.GetLoadingStatus()) or _waited > 8
                        local snd = Queue.GetActiveSound()
                        if snd then snd.TimePosition = math.max(0, timePos - 1.5) end
                    end)
                else
                    task.spawn(AutostartStation)
                end
            end)
        end

        btnCancel.MouseButton1Click:Connect(function() closeDialog(false) end)
        btnProceed.MouseButton1Click:Connect(function() closeDialog(true) end)

        openDialog()
end

local function _tryShowResumeModal()
        if _resumeModalShown then return end
        local savedSession = events.Main.SessionSaving.FetchSavedSession:InvokeServer()
        if not savedSession then return end

        local savedSongId  = savedSession.SoundId or 0
        local savedTimePos = savedSession.TimePosition or 0
        local savedCP      = savedSession.ContinuePlaying or {}

        if savedSongId == 0 or savedTimePos < 4 then return end
        _resumeModalShown = true

        -- Fetch metadata for the saved song
        -- FIX: Utilities không có GetAudioMetaDataAsync; dùng Audios.GetAudioMetadataAsync (batch)
        task.spawn(function()
                local metaList = Audios.GetAudioMetadataAsync({savedSongId})
                local metadata  = metaList and metaList[1] or nil
                _buildResumeModal(savedSongId, savedTimePos, savedCP, metadata)
        end)
end

-- Hook: show modal the first time the NowPlaying panel becomes visible
NowPlaying:GetPropertyChangedSignal("Visible"):Connect(function()
        if NowPlaying.Visible and not _resumeModalShown then
                task.delay(0.35, _tryShowResumeModal)
        end
end)

LoadLastSession()

-- Check for valid saved session BEFORE AutostartStation.
-- If there is one, skip autostart now; the resume modal's
-- Dismiss/Cancel button will call AutostartStation as fallback.
-- This prevents a race condition where autostart's TransitionTo
-- coroutine overwrites the resume song's State after LoadSource.
do
        local _sv = events.Main.SessionSaving.FetchSavedSession:InvokeServer()
        if _sv and (_sv.SoundId or 0) ~= 0 and (_sv.TimePosition or 0) >= 4 then
                _hasValidResume = true
        end
end

if not _hasValidResume then
        AutostartStation()
end

-- Auto-show resume modal 2s after startup (no need to open NowPlaying manually)
task.delay(2, function()
        if not _resumeModalShown then
                _tryShowResumeModal()
        end
end)

Players.PlayerRemoving:Connect(function(Player)
        if Player == client then
                SaveCurrentSession()
                -- FIX: Force write ngay lập tức, không đợi debounce 1s
                -- Tránh trường hợp game đóng trước khi loop kịp chạy
                if _mastersSaveImmediate then
                        pcall(_mastersSaveImmediate)
                end
        end
end)
]]



local fn, err = loadstring(_handlerSrc, "@Masters/Handler")
if not fn then
    warn("[Masters] Handler parse error: "..tostring(err))
    return
end
setfenv(fn, handlerEnv)

-- ─── ONBOARDING GATE → then run Handler & show Interface ─────────────

-- Destroy Failsafe / Prepublish NGAY (trước onboarding) để logo không đè lên
for _, name in ipairs({"Failsafe", "Prepublish"}) do
    local sg = _pgu:FindFirstChild(name)
    if sg then sg:Destroy() end
end

-- Nếu Onboarding ScreenGui tồn tại → chờ signal xong mới vào app
if uiOnboarding and not workspace:GetAttribute("Masters_Installed") then
    uiOnboarding.Enabled = true
    -- Ẩn Interface trong lúc onboarding
    local _iface = ui:FindFirstChild("Interface")
    if _iface then _iface.Visible = false end

    -- Đợi signal từ onboarding (X hoặc close sau install)
    _onboardingSignal.Event:Wait()

    -- Không Destroy để có thể reopen, chỉ disable
    pcall(function() uiOnboarding.Enabled = false end)
else
    -- Không có Onboarding → vào thẳng
end

-- Khởi động Handler
task.spawn(fn)

-- Hiện Interface chính
local _iface = ui:FindFirstChild("Interface")
if _iface then _iface.Visible = true end

print("[Masters] Executor Port loaded ✓")
